import { typedHandler } from "../utils/handler";
import { ApiError } from "../middleware/errorHandler";

import { eq, desc, and, inArray, isNotNull, sql } from "drizzle-orm";
import * as schema from "../../../src/db/schema";
import { OpenAPIHono } from "@hono/zod-openapi";

import { AppEnv, logSystemError, ensureAdmin, getDb } from "../middleware";
import Stripe from "stripe";
import { sendZulipMessage } from "../../utils/zulip";
import {
  getProductsRoute,
  createCheckoutSessionRoute,
  getOrdersRoute,
  updateOrderStatusRoute,
} from "../../../shared/routes/store";

export const storeRouter = new OpenAPIHono<AppEnv>();

// Webhook endpoint - must be before auth middleware since Stripe calls it
// Using native Hono route since webhook doesn't follow OpenAPI pattern (Stripe signature verification)
storeRouter.post("/webhook", async (c) => {
    try {
      const stripeKey = c.env.STRIPE_SECRET_KEY;
      const endpointSecret = c.env.STRIPE_WEBHOOK_SECRET;
      const signature = c.req.header("stripe-signature");

      if (!stripeKey || !endpointSecret || !signature) {
        throw new ApiError("Missing stripe signature", 400);
      }

      const stripe = new Stripe(stripeKey);
      let event: Stripe.Event;

      try {
        const rawBody = await c.req.text();
        event = stripe.webhooks.constructEvent(
          rawBody,
          signature,
          endpointSecret
        );
      } catch (err: unknown) {
        const message = err instanceof Error ? err.message : "Unknown error";
        console.error(`[Webhook] Signature verification failed: ${message}`);
        throw new ApiError(`Invalid signature`, 400);
      }

      if (event.type === "checkout.session.completed") {
        const session = event.data.object as Stripe.Checkout.Session;
        const db = getDb(c);

        // Fulfill order
        const metadata = session.metadata;
        const cartItems = metadata?.cartItems ? JSON.parse(metadata.cartItems) : [];

        const shippingName = (session as { shipping_details?: { name?: string | null } }).shipping_details?.name || null;

        await db
          .insert(schema.orders)
          .values({
            id: session.id,
            stripeSessionId: session.id,
            customerEmail: session.customer_details?.email || "unknown",
            shippingName: shippingName,
            totalCents: session.amount_total || 0,
            status: "paid",
            createdAt: new Date().toISOString(),
          })
          .run();

        // Deplete inventory
        for (const item of cartItems) {
          await db
            .update(schema.products)
            .set({ stockCount: sql`${schema.products.stockCount} - ${item.q}` })
            .where(
              and(
                eq(schema.products.id, item.id),
                isNotNull(schema.products.stockCount)
              )
            )
            .run();
        }

        // Alert team
        const totalAmount = session.amount_total ? (session.amount_total / 100).toFixed(2) : "0.00";
        const customerEmail = session.customer_details?.email || "Unknown Email";
        const message = `ðŸ›ï¸ **New Order Received!**\n\n**Order ID**: ${session.id}\n**Customer**: ${customerEmail}\n**Total**: $${totalAmount}\n\n[View Dashboard](https://aresweb.org/admin)`;
        await sendZulipMessage(c.env, "general", "Store Orders", message);
      }

      return c.json({ success: true }, 200);
    } catch (err: unknown) {
      logSystemError(getDb(c), "webhook_error", String(err));
      throw new ApiError("Webhook fulfillment failed", 500);
    }
  }
);

// Apply ensureAdmin middleware to orders routes
storeRouter.use("/orders/*", ensureAdmin);
storeRouter.use("/orders", ensureAdmin);

storeRouter.openapi(getProductsRoute, typedHandler<typeof getProductsRoute>(async (c) => {
    const db = getDb(c);
    const products = await db
      .select()
      .from(schema.products)
      .where(eq(schema.products.active, 1))
      .all();

    type Product = typeof schema.products.$inferSelect;
    return c.json(
      products.map((p: Product) => ({
        ...p,
        description: p.description || null,
        imageUrl: p.imageUrl || null,
        stockCount: p.stockCount ?? null,
      })),
      200
    );
}));

storeRouter.openapi(createCheckoutSessionRoute, typedHandler<typeof createCheckoutSessionRoute>(async (c) => {
    const body = c.req.valid("json");
    const { items, successUrl, cancelUrl } = body;
    const stripeKey = c.env.STRIPE_SECRET_KEY;
    if (!stripeKey) {
      throw new Error("STRIPE_SECRET_KEY is not configured.");
    }

    const stripe = new Stripe(stripeKey);
    const db = getDb(c);

    // Fetch product details
    const productIds = items.map((i: { productId: string }) => i.productId);
    const products = await db
      .select()
      .from(schema.products)
      .where(
        and(
          inArray(schema.products.id, productIds),
          eq(schema.products.active, 1)
        )
      )
      .all();

    type Product = typeof schema.products.$inferSelect;
    const productMap = new Map<string, Product>(products.map((p: Product) => [p.id, p]));

    const lineItems = items.map((item: { productId: string; quantity: number }) => {
      const product = productMap.get(item.productId);
      if (!product) {
        throw new Error(`Product ${item.productId} not found or inactive.`);
      }
      return {
        price_data: {
          currency: "usd",
          product_data: {
            name: product.name,
            images: product.imageUrl ? [product.imageUrl] : [],
          },
          unit_amount: product.priceCents,
        },
        quantity: item.quantity,
      };
    });

    const session = await stripe.checkout.sessions.create({
      payment_method_types: ["card"],
      line_items: lineItems,
      metadata: {
        cartItems: JSON.stringify(items.map((i: { productId: string; quantity: number }) => ({ id: i.productId, q: i.quantity })))
      },
      mode: "payment",
      success_url: successUrl,
      cancel_url: cancelUrl,
      shipping_address_collection: {
        allowed_countries: ["US", "CA"],
      },
    });

    if (!session.url) {
      throw new Error("Stripe session URL is null");
    }

    return c.json(
      {
        sessionId: session.id,
        url: session.url,
      },
      200
    );
}));

storeRouter.openapi(getOrdersRoute, typedHandler<typeof getOrdersRoute>(async (c) => {
    const db = getDb(c);
    const orders = await db
      .select()
      .from(schema.orders)
      .orderBy(desc(schema.orders.createdAt))
      .all();

    type Order = typeof schema.orders.$inferSelect;
    return c.json({ orders }, 200);
}));

storeRouter.openapi(updateOrderStatusRoute, typedHandler<typeof updateOrderStatusRoute>(async (c) => {
    const { id } = c.req.valid("param");
    const body = c.req.valid("json");
    const db = getDb(c);
    await db.update(schema.orders).set({ status: body.fulfillment_status }).where(eq(schema.orders.id, id)).run();
    return c.json({ success: true }, 200);
}));

export default storeRouter;

﻿import { typedHandler } from "../utils/handler";
import { OpenAPIHono } from "@hono/zod-openapi";
import { eq, ne, desc, asc, count } from "drizzle-orm";
import * as schema from "../../../src/db/schema";
import { siteConfig } from "../../utils/site.config";
import { AppEnv, getSocialConfig, getDb } from "../middleware";
import { sendZulipMessage } from "../../utils/zulipSync";
import { calculateIRV } from "../../utils/irvCalculator";
import { zulipWebhookRoute } from "../../../shared/routes/webhooks";
import { safeWaitUntil } from "../utils/safeWaitUntil";

export const zulipWebhookRouter = new OpenAPIHono<AppEnv>();

// SEC-F01: Timing-safe comparison for webhook tokens (Length-Independent)
function timingSafeEqual(a: string, b: string): boolean {
  const enc = new TextEncoder();
  const aBuf = enc.encode(a);
  const bBuf = enc.encode(b);

  const MAX_TOKEN_LENGTH = 128;

  let result = 0;
  for (let i = 0; i < MAX_TOKEN_LENGTH; i++) {
    const aByte = i < aBuf.length ? aBuf[i] : 0;
    const bByte = i < bBuf.length ? bBuf[i] : 0;
    result |= aByte ^ bByte;
  }
  return result === 0 && aBuf.length === bBuf.length;
}

// â”€â”€ POST /webhooks/zulip â€” Handle outgoing webhook from Zulip â”€â”€â”€â”€â”€â”€â”€â”€
zulipWebhookRouter.openapi(zulipWebhookRoute, typedHandler<typeof zulipWebhookRoute>(async (c) => {
  const body = c.req.valid("json");

  const config = await getSocialConfig(c);
  const expectedToken = config.ZULIP_WEBHOOK_TOKEN;
  if (!expectedToken) {
    return c.json({ content: "âŒ Webhook token not configured on server." }, 401);
  }
  if (!timingSafeEqual(body.token, expectedToken)) {
    return c.json({ content: "âŒ Unauthorized: Invalid webhook token." }, 401);
  }

  const rawContent = body.message?.content || "";
  const cleaned = rawContent.replace(/@\*\*[^*]+\*\*/g, "").trim();
  
  if (!cleaned) {
    return c.json({ content: "ðŸ¤– Hello! I am the ARES Bot. Type `!help` to see what I can do." }, 200);
  }

  const args = cleaned.match(/[^\s"']+|"([^"]*)"|'([^']*)'/g)?.map((arg: string) => 
    arg.replace(/^["']|["']$/g, "")
  ) || [];
  
  const command = args[0]?.toLowerCase();

  const PRIVILEGED_COMMANDS = ["!task", "!broadcast"];
  const db = getDb(c);

  if (PRIVILEGED_COMMANDS.includes(command || "")) {
    const senderEmail = body.message?.sender_email;
    if (senderEmail) {
      const userResult = await db
        .select({ role: schema.user.role })
        .from(schema.user)
        .where(
          eq(schema.user.email, senderEmail)
        )
        .get();

      if (!userResult || !["admin", "author"].includes(userResult.role || "")) {
        return c.json({ content: `ðŸ”’ Permission denied. \`${command}\` requires admin or author privileges. Your Zulip email (${senderEmail}) is not linked to an authorized ARESWEB account.` }, 200);
      }
    }
  }

  try {
    switch (command) {
      case "!help":
        return c.json({
          content: [
            "ðŸ¤– **ARES Bot Commands**",
            "",
            "| Command | Description |",
            "|---|---|",
            "| `!tasks` | List open tasks |",
            "| `!task <title>` | Create a new task |",
            "| `!task <#> done` | Mark a task as Done |",
            "| `!stats` | ARESWEB quick stats |",
            "| `!inquiries` | Pending inquiry count |",
            "| `!events` | Upcoming events |",
            "| `!broadcast <stream> <msg>` | Broadcast an admin msg |",
            "| `!rcv` | Ranked choice voting (type `!rcv` for help) |",
            "| `!help` | Show this help |",
          ].join("\n"),
        }, 200);

      case "!tasks": {
        const taskResults = await db
          .select({
            id: schema.tasks.id,
            title: schema.tasks.title,
            status: schema.tasks.status,
            assignee_name: schema.userProfiles.nickname,
          })
          .from(schema.tasks)
          .leftJoin(schema.userProfiles, eq(schema.tasks.assignedTo, schema.userProfiles.userId))
          .where(ne(schema.tasks.status, "done"))
          .orderBy(asc(schema.tasks.sortOrder), desc(schema.tasks.createdAt))
          .limit(15)
          .all();

        if (taskResults.length === 0) {
          return c.json({ content: "ðŸ“‹ **Task Board** â€” No open tasks." }, 200);
        }
        const lines = taskResults.map((item, i) => {
          const status = item.status ? `\`${item.status}\`` : "â€”";
          const assignee = item.assignee_name ? `@${item.assignee_name}` : "";
          return `${i + 1}. **${item.title}** ${status} ${assignee}`;
        });

        const totalRes = await db.select({ count: count(schema.tasks.id) }).from(schema.tasks).get();
        const total = Number(totalRes?.count || taskResults.length);

        return c.json({
          content: `ðŸ“‹ **Task Board** (${total} total)\n\n${lines.join("\n")}`,
        }, 200);
      }

      case "!task": {
        const taskArgs = args.slice(1);
        if (taskArgs.length === 0) {
          return c.json({ content: "Usage: `!task <title>` to create, or `!task <#> done` to complete." }, 200);
        }

        const indexArg = parseInt(taskArgs[0]);
        if (!isNaN(indexArg) && taskArgs[1]?.toLowerCase() === "done") {
          const openTasks = await db
            .select({ id: schema.tasks.id, title: schema.tasks.title })
            .from(schema.tasks)
            .where(ne(schema.tasks.status, "done"))
            .orderBy(asc(schema.tasks.sortOrder), desc(schema.tasks.createdAt))
            .limit(15)
            .all();
          const target = openTasks[indexArg - 1];
          if (!target) return c.json({ content: `âŒ No task at index ${indexArg}.` }, 200);

          await db
            .update(schema.tasks)
            .set({ status: "done", updatedAt: new Date().toISOString() })
            .where(eq(schema.tasks.id, target.id));

          return c.json({ content: `âœ… **${target.title}** marked as Done!` }, 200);
        }

        const title = taskArgs.join(" ");
        const senderEmail = body.message?.sender_email;
        let creatorId = "system";
        if (senderEmail) {
          const senderUser = await db
            .select({ id: schema.user.id })
            .from(schema.user)
            .where(eq(schema.user.email, senderEmail))
            .get();
          if (senderUser?.id) creatorId = senderUser.id;
        }

        const taskId = crypto.randomUUID();
        const now = new Date().toISOString();
        await db
          .insert(schema.tasks)
          .values({
            id: taskId,
            title,
            description: `Created via Zulip by ${body.message.sender_full_name}`,
            status: "todo",
            priority: "normal",
            sortOrder: 0,
            createdBy: creatorId,
            createdAt: now,
            updatedAt: now,
          });

        return c.json({ content: `âœ… Created task: **${title}**` }, 200);
      }

      case "!stats": {
        const [postsRes, eventsRes, usersRes, inquiriesRes] = await Promise.all([
          db.select({ count: count(schema.posts.slug) }).from(schema.posts).where(eq(schema.posts.isDeleted, 0)).get(),
          db.select({ count: count(schema.events.id) }).from(schema.events).where(eq(schema.events.isDeleted, 0)).get(),
          db.select({ count: count(schema.userProfiles.userId) }).from(schema.userProfiles).get(),
          db.select({ count: count(schema.inquiries.id) }).from(schema.inquiries).where(eq(schema.inquiries.status, "pending")).get(),
        ]);

        return c.json({
          content: [
            "ðŸ“Š **ARESWEB Quick Stats**",
            "",
            `| Metric | Count |`,
            `|---|---|`,
            `| Published Posts | ${postsRes?.count || 0} |`,
            `| Active Events | ${eventsRes?.count || 0} |`,
            `| Team Members | ${usersRes?.count || 0} |`,
            `| Pending Inquiries | ${inquiriesRes?.count || 0} |`,
          ].join("\n"),
        }, 200);
      }

      case "!inquiries": {
        const result = await db.select({ count: count(schema.inquiries.id) }).from(schema.inquiries).where(eq(schema.inquiries.status, "pending")).get();
        const countValue = Number(result?.count || 0);
        return c.json({
          content: countValue > 0
            ? `ðŸ”” **${countValue} pending inquir${countValue === 1 ? "y" : "ies"}** â€” [Review in Dashboard](${siteConfig.urls.base}/dashboard?tab=inquiries)`
            : "âœ… No pending inquiries! All caught up.",
        }, 200);
      }

      case "!events": {
        // We use greater than or equal to today using standard string comparison
        const today = new Date().toISOString().split('T')[0];
        
        // Use a SQL template string for the where clause since it's cleaner than building the operator for dates sometimes
        // Wait, Drizzle natively supports greater than or equal with `gte`
        const { gte, and } = await import("drizzle-orm");
        const results = await db
          .select({
            title: schema.events.title,
            dateStart: schema.events.dateStart,
            dateEnd: schema.events.dateEnd,
            location: schema.events.location,
          })
          .from(schema.events)
          .where(
            and(
              eq(schema.events.isDeleted, 0),
              eq(schema.events.status, "published"),
              gte(schema.events.dateStart, today)
            )
          )
          .orderBy(asc(schema.events.dateStart))
          .limit(10)
          .all();

        if (!results || results.length === 0) {
          return c.json({ content: "ðŸ“… No upcoming events scheduled." }, 200);
        }

        const lines = results.map((e) => {
          const dtStart = new Date(String(e.dateStart)).toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" });
          const dtEnd = e.dateEnd ? ` - ${new Date(String(e.dateEnd)).toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" })}` : "";
          return `â€¢ **${e.title}** â€” ${dtStart}${dtEnd}${e.location ? ` @ ${e.location}` : ""}`;
        });

        return c.json({
          content: `ðŸ“… **Upcoming Events** (${results.length})\n\n${lines.join("\n")}`,
        }, 200);
      }

      case "!broadcast": {
        const streamTarget = args[1];
        const msgCore = args.slice(2).join(" ");
        if (!streamTarget || !msgCore) {
           return c.json({ content: "âš ï¸ Usage: `!broadcast <stream> <message...>` (use quotes for stream names with spaces)" }, 200);
        }
        
        const broadcastContent = `${msgCore}\n\n*â€” Broadcasted by ${body.message.sender_full_name} via ARES Bot*`;

        safeWaitUntil(c.executionCtx, (async () => {
          const socialConfig = await getSocialConfig(c);
          await sendZulipMessage(socialConfig, streamTarget, "Broadcast", broadcastContent).catch((err) => {
            console.error("Failed to send broadcast message:", err);
          });
        })(), "Failed to send Zulip broadcast");

        return c.json({ content: `âœ… Broadcast dispatched to \`${streamTarget}\`.` }, 200);
      }

      case "!rcv": {
        const rcvSubcommand = args[1]?.toLowerCase();
        
        if (!rcvSubcommand || rcvSubcommand === "help") {
          return c.json({
            content: [
              "ðŸ—³ï¸ **Ranked Choice Voting (IRV)**",
              "",
              "| Command | Description |",
              "|---|---|",
              "| `!rcv create \"Title\" \"Opt 1\" \"Opt 2\"` | Create a poll (Admin) |",
              "| `!rcv vote <id> 2 1 3` | Rank options (1st=2, 2nd=1...) |",
              "| `!rcv status <id>` | View poll options & vote count |",
              "| `!rcv tally <id>` | Close poll & calculate winner (Admin) |",
            ].join("\n"),
          }, 200);
        }

        const senderEmail = body.message?.sender_email;

        // Helper to check admin
        const checkAdmin = async () => {
          if (!senderEmail) return false;
          const userRecord = await db
            .select({ role: schema.user.role })
            .from(schema.user)
            .where(eq(schema.user.email, senderEmail))
            .get();
          return !!userRecord && ["admin", "author"].includes(userRecord.role || "");
        };

        if (rcvSubcommand === "create") {
          if (!(await checkAdmin())) {
            return c.json({ content: "ðŸ”’ Permission denied. `!rcv create` requires admin privileges." }, 200);
          }
          const title = args[2];
          const options = args.slice(3);
          if (!title || options.length < 2) {
             return c.json({ content: "âš ï¸ Usage: `!rcv create \"Title\" \"Option 1\" \"Option 2\" ...`" }, 200);
          }
          
          const pollId = Math.random().toString(36).slice(2, 6);
          const pollData = {
            title,
            options,
            votes: {} as Record<string, number[]>,
            active: true
          };

          await db
            .insert(schema.settings)
            .values({ key: `rcv_poll_${pollId}`, value: JSON.stringify(pollData) });

          const optionsList = options.map((opt: string, i: number) => `${i + 1}ï¸âƒ£ **${opt}**`).join("\n");
          return c.json({
            content: `ðŸ“Š **Poll Created: ${title}** (ID: \`${pollId}\`)\n\n**Options:**\n${optionsList}\n\nTo vote, reply with: \`!rcv vote ${pollId} <1st_choice> <2nd_choice>...\`\nExample ranking option 2 first, then 1: \`!rcv vote ${pollId} 2 1\``
          }, 200);
        }

        const pollId = args[2];
        if (!pollId) {
          return c.json({ content: "âš ï¸ Please specify a poll ID." }, 200);
        }
        
        const pollRecord = await db
          .select({ value: schema.settings.value })
          .from(schema.settings)
          .where(eq(schema.settings.key, `rcv_poll_${pollId}`))
          .get();

        if (!pollRecord) {
          return c.json({ content: `âŒ Poll \`${pollId}\` not found.` }, 200);
        }

        const poll = JSON.parse(pollRecord.value as string);

        if (rcvSubcommand === "status") {
          const optionsList = poll.options.map((opt: string, i: number) => `${i + 1}ï¸âƒ£ **${opt}**`).join("\n");
          const voteCount = Object.keys(poll.votes).length;
          return c.json({
             content: `ðŸ“Š **Poll: ${poll.title}** (ID: \`${pollId}\`) - ${poll.active ? "ðŸŸ¢ Active" : "ðŸ”´ Closed"}\n\n**Options:**\n${optionsList}\n\n**Total Votes:** ${voteCount}`
          }, 200);
        }

        if (rcvSubcommand === "vote") {
          if (!poll.active) {
            return c.json({ content: "âŒ This poll is closed." }, 200);
          }
          if (!senderEmail) return c.json({ content: "âŒ Could not identify voter." }, 200);
          
          const rankings = args.slice(3).map((n: string) => parseInt(n) - 1); // 0-indexed
          
          if (rankings.length === 0 || rankings.some((r: number) => isNaN(r) || r < 0 || r >= poll.options.length)) {
            return c.json({ content: `âš ï¸ Invalid ranking. Use numbers 1 to ${poll.options.length} separated by spaces.` }, 200);
          }

          if (new Set(rankings).size !== rankings.length) {
            return c.json({ content: "âš ï¸ Invalid ranking. Do not repeat options." }, 200);
          }

          poll.votes[senderEmail] = rankings;
          
          await db
            .update(schema.settings)
            .set({ value: JSON.stringify(poll), updatedAt: new Date().toISOString() })
            .where(eq(schema.settings.key, `rcv_poll_${pollId}`));

          return c.json({ content: `âœ… Your vote for \`${pollId}\` has been recorded! (You ranked ${rankings.length} option(s))` }, 200);
        }

        if (rcvSubcommand === "tally") {
           if (!(await checkAdmin())) {
            return c.json({ content: "ðŸ”’ Permission denied. `!rcv tally` requires admin privileges." }, 200);
          }
          if (!poll.active) {
             return c.json({ content: "âš ï¸ This poll is already closed." }, 200);
          }

          poll.active = false;
          await db
            .update(schema.settings)
            .set({ value: JSON.stringify(poll), updatedAt: new Date().toISOString() })
            .where(eq(schema.settings.key, `rcv_poll_${pollId}`));

          const ballots = Object.values(poll.votes) as number[][];
          if (ballots.length === 0) {
            return c.json({ content: `ðŸ”´ **Poll Closed: ${poll.title}**\nNo votes were cast.` }, 200);
          }

          const result = calculateIRV(poll.options.length, ballots);

          let resultMsg = `ðŸ”´ **Poll Closed: ${poll.title}**\n**Total Ballots:** ${ballots.length}\n\n`;
          
          for (const round of result.rounds) {
             resultMsg += `**Round ${round.roundNumber}:**\n`;
             for (const [cIdx, votes] of Object.entries(round.voteCounts)) {
                resultMsg += `- ${poll.options[parseInt(cIdx)]}: ${votes} votes\n`;
             }
             if (round.eliminatedCandidates.length > 0) {
                const elimNames = round.eliminatedCandidates.map((idx: number) => poll.options[idx]).join(", ");
                resultMsg += `âŒ *Eliminated: ${elimNames}*\n`;
             }
             resultMsg += "\n";
          }

          if (result.winner !== undefined) {
             resultMsg += `ðŸ† **WINNER: ${poll.options[result.winner]}**!`;
          } else if (result.tied !== undefined) {
             const tiedNames = result.tied.map((idx: number) => poll.options[idx]).join(" and ");
             resultMsg += `ðŸ¤ **TIE between: ${tiedNames}**!`;
          }

          return c.json({ content: resultMsg }, 200);
        }

        return c.json({ content: "âš ï¸ Unknown `!rcv` subcommand." }, 200);
      }

      default:
        if (body.message?.type === "stream" && (body.message.topic || body.message.subject)) {
          const topicStr = body.message.topic || body.message.subject || "";
          const topicParts = topicStr.split("/");
          if (topicParts.length >= 2 && ["post", "event", "doc"].includes(topicParts[0])) {
            const targetType = topicParts[0];
            const targetId = topicParts.slice(1).join("/");

            const existingUser = await db
              .select({ id: schema.user.id, role: schema.user.role })
              .from(schema.user)
              .where(eq(schema.user.email, body.message.sender_email || ""))
              .get();

            if (!existingUser || existingUser.role === "unverified" || !existingUser.id) {
              return c.json({ content: "" }, 200);
            }

            const userId = existingUser.id;

            try {
              await db
                .insert(schema.comments)
                .values({
                  id: (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") ? crypto.randomUUID() : `cmt-${Date.now()}-${Math.random()}`,
                  targetType: targetType,
                  targetId: targetId,
                  userId: userId,
                  content: rawContent,
                  zulipMessageId: String(body.trigger === "message" ? body.message.id : 0),
                  createdAt: new Date().toISOString()
                });
              return c.json({ content: "" }, 200);
            } catch {
              /* ignore sync error */
            }
          }
        }

        if (rawContent.includes("@**")) {
           return c.json({
             content: `â“ Unknown command: \`${command || "(empty)"}\`. Type \`!help\` for available commands.`,
           }, 200);
        }
        
        return c.json({ content: "" }, 200);
    }
  } catch (err) {
    return c.json({
      content: `âŒ Command failed: ${(err as Error)?.message || "Unknown error"}`,
    }, 200);
  }
}));

export default zulipWebhookRouter;

