import { useState, useEffect } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { useNavigate, useParams } from "@tanstack/react-router";
import { toast } from "sonner";
import { useRichEditor } from "./editor/useRichEditor";
import RichEditorToolbar from "./editor/RichEditorToolbar";
import { CopilotMenu } from "./editor/CopilotMenu";
import AssetPickerModal from "./AssetPickerModal";
import { DEFAULT_coverImage } from "../utils/constants";
import { useAdminSettings } from "../hooks/useAdminSettings";
import { useImageUpload } from "../hooks/useImageUpload";
import { z } from "zod";
import { postSchema, PostPayload } from "@shared/schemas/postSchema";
import { useGetAdminPost, useSavePost, useUpdatePost, useDeletePost, type SavePostResponse, type UpdatePostResponse } from "../api";
import { useModal } from "../contexts/ModalContext";
import CoverAssetPicker from "./editor/CoverAssetPicker";
import SocialSyndicationGrid from "./editor/SocialSyndicationGrid";
import EditorFooter from "./editor/EditorFooter";
import { useForm } from "@tanstack/react-form";

import { RefreshCw } from "lucide-react";

import SeasonPicker from "./SeasonPicker";

import { CollaborativeEditorRoom, useCollaborativeEditor } from "./editor/CollaborativeEditorRoom";
import VersionHistorySidebar from "./editor/VersionHistorySidebar";

import ZulipThread from "./ZulipThread";

function BlogEditorInner({ editSlug, userRole, roomId }: { editSlug?: string, userRole?: string | unknown, roomId?: string | null }) {
  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const modal = useModal();

  // Custom Hooks
  const { availableSocials } = useAdminSettings();
  const { uploadFile, isUploading: isUploadingCover, setErrorMsg: setUploadError } = useImageUpload();
  const [errorMsg, setErrorMsg] = useState("");
  const [isCoverPickerOpen, setIsCoverPickerOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  const form = useForm<PostPayload>({
    defaultValues: {
      title: "",
      thumbnail: DEFAULT_coverImage,
      ast: {},
      socials: {
        discord: true,
        bluesky: true,
        slack: false,
        teams: false,
        gchat: false,
        facebook: false,
        twitter: false,
        instagram: false
      },
      isDraft: false,
      publishedAt: "",
      seasonId: undefined
    }
  });


  const thumbnailValue = form.useStore((s) => s.values.thumbnail);
  const titleValue = form.useStore((s) => s.values.title);
  const socialsValue = form.useStore((s) => s.values.socials);
  const { ydoc, provider } = useCollaborativeEditor();
  const editor = useRichEditor({ 
    placeholder: "<p>Start drafting your robotics article here. Tell us about your journey to Einstein...</p>",
    ydoc,
    provider
  });

  // Use standard API query instead of custom useEntityFetch
  const { data: postRes, isLoading, isError } = useGetAdminPost(editSlug || "");

  useEffect(() => {
    if (postRes && postRes.post) {
      const post = postRes.post;
      form.setFieldValue("title", post.title || "");
      form.setFieldValue("publishedAt", post.publishedAt || "");
      form.setFieldValue("seasonId", post.seasonId ? Number(post.seasonId) : undefined);
      form.setFieldValue("thumbnail", post.thumbnail || DEFAULT_coverImage);
      form.setFieldValue("ast", post.ast ? JSON.parse(post.ast) : {});
      form.setFieldValue("socials", (postRes as unknown as { socials?: Record<string, boolean> }).socials || {});
      if (editor && post.ast) {
        // In collaborative mode, avoid overwriting active live edits with the static DB snapshot.
        const shouldSetContent = !ydoc || ydoc.getXmlFragment("default").length === 0;

        if (shouldSetContent) {
          try {
            editor.commands.setContent(JSON.parse(post.ast));
          } catch (e) {
            console.error("Failed to parse existing AST", e);
          }
        }
      }
    }

  }, [postRes, form, editor, ydoc]);

  const saveMutation = useSavePost({
    onSuccess: (data: SavePostResponse) => {
      queryClient.invalidateQueries({ queryKey: ["posts"] });
      queryClient.invalidateQueries({ queryKey: ["admin_posts"] });

      if (data.warning) {
        toast.info("Post saved successfully, but social syndication had issues:\n\n" + data.warning);
      }

      navigate({ to: "/dashboard" });
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Publication failed");
    }
  });

  const updateMutation = useUpdatePost({
    onSuccess: (data: UpdatePostResponse) => {
      queryClient.invalidateQueries({ queryKey: ["posts"] });
      queryClient.invalidateQueries({ queryKey: ["admin_posts"] });
      if (editSlug) queryClient.invalidateQueries({ queryKey: ["post", editSlug] });

      if (data.warning) {
        toast.info("Post updated successfully, but social syndication had issues:\n\n" + data.warning);
      }

      navigate({ to: `/blog/${data.slug || editSlug}` });
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Update failed");
    }
  });

  const deleteMutation = useDeletePost({
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["posts"] });
      queryClient.invalidateQueries({ queryKey: ["admin_posts"] });
      navigate({ to: "/dashboard/manage_blog" });
    },
    onError: () => {
      setErrorMsg("Failed to delete the post. Please try again.");
    }
  });

  const onFormSubmit = (isDraft = false) => {
    if (!editor) return;
    const ast = editor.getJSON();
    const formValue = form.state.values;
    const payload = { ...formValue, ast, isDraft, thumbnail: formValue.thumbnail === DEFAULT_coverImage ? "" : formValue.thumbnail };
    if (editSlug) {
      updateMutation.mutate({ slug: editSlug, body: payload });
    } else {
      saveMutation.mutate(payload);
    }
  };

  const handleDelete = async () => {
    if (!editSlug) return;
    const confirmed = await modal.confirm({
      title: "Delete Post",
      description: "Are you sure you want to permanently delete this post?",
      confirmText: "Delete",
      destructive: true,
    });
    if (!confirmed) return;

    deleteMutation.mutate(editSlug);
  };


  if (isLoading) return <div className="flex items-center justify-center py-20"><RefreshCw className="animate-spin text-ares-red" size={32} /></div>;

  if (!editor) return <div className="text-marble animate-pulse font-mono tracking-widest text-sm">Booting Editor System...</div>;

  return (

      <div className="flex flex-col gap-6 w-full relative h-full">
        <div className="flex flex-col gap-6 flex-1 min-w-0">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight mb-2">
            {editSlug ? "Edit Entry" : "Publish Entry"}
          </h2>
          <p className="text-marble/60 text-sm">
            {editSlug ? "Modify an existing engineering or outreach update." : "Draft rich-text engineering and outreach updates."}
          </p>
        </div>

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          COMMUNICATION FAULT: Failed to retrieve record from server.
        </div>
      )}

      {/* Settings Grid */}
      <div className="flex flex-col md:flex-row gap-4 mt-2">
        <div className="flex-1">
          <label htmlFor="post-title" className="block text-xs font-bold text-marble/60 uppercase tracking-wider mb-2">Post Title</label>
          <form.Field
            name="title"
            children={(field) => (
              <>
                <input
                  id="post-title"
                  type="text"
                  name={field.name}
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30 focus:outline-none focus:ring-1 focus:ring-ares-red focus:border-ares-red transition-all shadow-inner lg:text-lg"
                  placeholder='e.g. Our Road to State'
                />
                {field.state.meta.errors.length > 0 && (
                  <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                )}
              </>
            )}
          />
        </div>
        <div className="flex-1">
          <CoverAssetPicker
            label="Cover Image"
            coverImage={thumbnailValue || DEFAULT_coverImage}
            isUploading={isUploadingCover}
            onLibraryClick={() => setIsCoverPickerOpen(true)}
            onUrlChange={(url) => form.setFieldValue("thumbnail", url)}
            onFileChange={async (file) => {
              try {
                setUploadError("");
                const { url } = await uploadFile(file);
                form.setFieldValue("thumbnail", url);
              } catch {
                // handled by hook
              }
            }}
          />
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1 md:max-w-xs">
          <label htmlFor="post-published-at" className="block text-xs font-bold text-marble/60 uppercase tracking-wider mb-2">Schedule Publish Time</label>
          <form.Field
            name="publishedAt"
            children={(field) => (
              <input
                id="post-published-at" type="datetime-local"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value)}
                className="w-full bg-black border border-white/10 ares-cut-sm px-4 py-3 text-marble placeholder-marble/30 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
              />
            )}
          />
        </div>
        <div className="flex-1 md:max-w-xs">
          <form.Field
            name="seasonId"
            children={(field) => (
              <SeasonPicker value={field.state.value || ""} onChange={(val) => field.handleChange(val ? Number(val) : undefined)} />
            )}
          />
        </div>
      </div>



      {/* ===== Unified Rich Editor ===== */}
      <div className="flex items-center gap-2">
        <div className="flex-1"><RichEditorToolbar editor={editor} documentTitle={titleValue} /></div>
      </div>
      <CopilotMenu editor={editor} />

      {/* Cover Image Picker Modal */}
      <AssetPickerModal
        isOpen={isCoverPickerOpen}
        onClose={() => setIsCoverPickerOpen(false)}
        onSelect={(url) => {
          form.setFieldValue("thumbnail", url);
          setIsCoverPickerOpen(false);
        }}
      />

      <EditorFooter
        errorMsg={errorMsg || ""}
        isPending={saveMutation.isPending}
        isEditing={!!editSlug}
        onDelete={handleDelete}
        onSaveDraft={() => onFormSubmit(true)}
        onPublish={() => onFormSubmit(false)}
        deleteText="DELETE"
        updateText="UPDATE ENTRY"
        publishText={userRole === "author" ? "SUBMIT FOR REVIEW" : "PUBLISH ENTRY"}
        userRole={userRole}
        roundedClass="ares-cut"
        onShowHistory={roomId && editor ? () => setIsHistoryOpen(true) : undefined}
        extraControls={
          <SocialSyndicationGrid
            availableSocials={availableSocials}
            socials={socialsValue}
            onChange={(platform, val) => form.setFieldValue(`socials.${platform}`, val)}
            isEdit={!!editSlug}
          />
        }
      />

      {isHistoryOpen && roomId && editor && (
        <VersionHistorySidebar 
          roomId={roomId}
          editor={editor}
          onClose={() => setIsHistoryOpen(false)}
          historyUrl={editSlug ? `/api/posts/admin/${editSlug}/history` : undefined}
        />
      )}
      </div>

      {editSlug && postRes?.post && (
        <div className="w-full flex flex-col gap-6 mt-6">
          <ZulipThread
            stream={postRes.post.zulipStream || "blog"}
            topic={postRes.post.zulipTopic || `Blog: ${postRes.post.title}`}
          />
        </div>
      )}
    </div>
  );
}

export default function BlogEditor({ userRole }: { userRole?: string | unknown }) {
  const { editSlug } = useParams({ strict: false }) as Record<string, string>;

  const [draftId] = useState(() => `draft_blog_${crypto.randomUUID?.() || Math.random().toString(36).substring(2)}`);
  const roomId = editSlug ? `blog_${editSlug}` : draftId;

  return (
    <CollaborativeEditorRoom roomId={roomId}>
      <BlogEditorInner editSlug={editSlug} userRole={userRole} roomId={roomId} />
    </CollaborativeEditorRoom>
  );
}

﻿import { useState, useEffect, useRef, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, MapPin, CheckCircle } from "lucide-react";
import { toast } from "sonner";
import { useForm } from "@tanstack/react-form";
import { useQueryClient } from "@tanstack/react-query";
import { locationSchema } from "@shared/routes/locations";
import { z } from "zod";
import { useSaveLocation } from "../api";

interface CreateLocationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (locationName: string) => void;
}

export function CreateLocationModal({ isOpen, onClose, onSuccess }: CreateLocationModalProps) {
  const modalRef = useRef<HTMLDivElement>(null);
  const _queryClient = useQueryClient();
  const [errorMsg, setErrorMsg] = useState("");
  const [isSearchingOSM, setIsSearchingOSM] = useState(false);
  const [suggestions, setSuggestions] = useState<{ display_name: string }[]>([]);

  const form = useForm<z.infer<typeof locationSchema>>({
    defaultValues: {
      name: "",
      address: "",
      maps_url: "",
      isDeleted: 0
    }
  });

  const { Provider: FormProvider } = form;

  const resetForm = useCallback(() => {
    form.setFieldValue("name", "");
    form.setFieldValue("address", "");
    form.setFieldValue("maps_url", "");
    form.setFieldValue("isDeleted", 0);
    setSuggestions([]);
    setErrorMsg("");
  }, [form]);

  const saveMutation = useSaveLocation({
    onSuccess: (res) => {
      if (res.success) {
        toast.success("Venue record synchronized.");

        // Pass the new name back
        const formValues = form.state.values;
        onSuccess(formValues.name);

        resetForm();
      } else {
        setErrorMsg("Failed to save venue");
      }
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Network error.");
    }
  });

  // Debounced OSM Geocoding
  useEffect(() => {
    const timer = setTimeout(async () => {
      const addressQuery = form.state.values.address || "";
      if (!addressQuery || addressQuery.length < 4) {
        setSuggestions([]);
        return;
      }
      setIsSearchingOSM(true);
      try {
        const res = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(addressQuery)}&format=json&addressdetails=1&limit=5`);
        const data = await res.json() as { display_name: string }[];
        setSuggestions(data);
      } catch (err) {
        console.error("OSM Err:", err);
      } finally {
        setIsSearchingOSM(false);
      }
    }, 600);
    return () => clearTimeout(timer);
  }, [form.state.values.address]);

  const handleClose = useCallback(() => {
    resetForm();
    onClose();
  }, [resetForm, onClose]);

  const onFormSubmit = () => {
    setErrorMsg("");
    const formValue = form.state.values;
    saveMutation.mutate({ ...formValue, id: undefined });
  };

  // Keyboard handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (e.key === "Escape") {
        e.preventDefault();
        handleClose();
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, handleClose]);

  // Focus management
  useEffect(() => {
    if (isOpen) {
      const timer = setTimeout(() => {
        const titleInput = modalRef.current?.querySelector('#venue_name') as HTMLElement;
        if (titleInput) titleInput.focus();
      }, 50);
      return () => clearTimeout(timer);
    }
  }, [isOpen]);

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={handleClose}
            className="absolute inset-0 bg-black/70 backdrop-blur-sm"
          />
          <motion.div
            ref={modalRef}
            role="dialog"
            aria-modal="true"
            aria-labelledby="create-location-title"
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="relative w-full max-w-lg bg-obsidian border border-white/10 shadow-2xl ares-cut overflow-visible"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Header */}
            <div className="px-6 py-4 border-b border-white/10 bg-white/5 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-ares-red/20 rounded-lg">
                  <MapPin className="text-ares-red" size={20} />
                </div>
                <div>
                  <h2 id="create-location-title" className="text-xl font-bold text-white uppercase tracking-wide">
                    Register New Venue
                  </h2>
                </div>
              </div>
              <button
                onClick={handleClose}
                aria-label="Close modal"
                className="p-2 text-marble/60 hover:text-white hover:bg-white/10 rounded-lg transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            {/* Form */}
            <FormProvider>
              <form onSubmit={(e) => { e.preventDefault(); onFormSubmit(); }} className="p-6 space-y-5">
                {errorMsg && (
                  <div className="p-3 bg-ares-danger/10 border border-ares-danger/30 rounded text-ares-danger text-sm">
                    {errorMsg}
                  </div>
                )}

                <div className="flex flex-col gap-4">
                  <div>
                    <label htmlFor="venue_name" className="text-xs uppercase tracking-widest text-marble/90 font-bold mb-2 block">Alias (e.g. &apos;Mars Workspace&apos;) *</label>
                    <form.Field
                      name="name"
                      children={(field) => (
                        <>
                          <input
                            id="venue_name"
                            type="text"
                            name={field.name}
                            value={field.state.value}
                            onBlur={field.handleBlur}
                            onChange={(e) => field.handleChange(e.target.value)}
                            className="w-full bg-obsidian border border-white/10 rounded p-3 text-white focus:border-ares-cyan outline-none"
                            placeholder="Enter short venue name"
                          />
                          {field.state.meta.errors.length > 0 && (
                            <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                          )}
                        </>
                      )}
                    />
                  </div>

                  <div className="relative">
                    <label htmlFor="venue_address" className="text-xs uppercase tracking-widest text-marble/90 font-bold mb-2 block">Street Address (Auto-suggest) *</label>
                    <form.Field
                      name="address"
                      children={(field) => (
                        <>
                          <div className="relative">
                            <input
                              id="venue_address"
                              type="text"
                              name={field.name}
                              value={field.state.value}
                              onBlur={field.handleBlur}
                              onChange={(e) => field.handleChange(e.target.value)}
                              className="w-full bg-obsidian border border-white/10 rounded p-3 text-white focus:border-ares-cyan outline-none"
                              placeholder="Start typing an address..."
                              autoComplete="off"
                            />
                            {isSearchingOSM && <div className="absolute right-3 top-1/2 -translate-y-1/2 text-marble/50 text-xs">...</div>}
                          </div>
                          {field.state.meta.errors.length > 0 && (
                            <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                          )}
                        </>
                      )}
                    />

                    {suggestions.length > 0 && (
                      <div className="absolute z-20 w-full mt-1 bg-black border border-white/10 ares-cut-sm shadow-xl overflow-hidden">
                        {suggestions.map((s, i) => (
                          <button
                            key={i}
                            type="button"
                            className="w-full text-left p-3 hover:bg-ares-cyan hover:text-black border-b border-white/10 text-sm text-marble transition-colors last:border-0"
                            onClick={() => {
                              form.setFieldValue("address", s.display_name);
                              const mapsLink = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(s.display_name)}`;
                              form.setFieldValue("maps_url", mapsLink);
                              setSuggestions([]);
                            }}
                          >
                            {s.display_name}
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

              {/* Actions */}
              <div className="flex items-center justify-end gap-3 pt-4 border-t border-white/10">
                <button
                  type="button"
                  onClick={handleClose}
                  disabled={saveMutation.isPending}
                  className="px-5 py-2.5 text-sm font-bold text-marble/90 hover:text-white bg-white/5 hover:bg-white/10 transition-colors uppercase tracking-widest ares-cut-sm disabled:opacity-50"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={saveMutation.isPending}
                  className="px-5 py-2.5 text-sm font-bold uppercase tracking-widest bg-ares-cyan text-black hover:bg-white transition-colors ares-cut-sm disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                >
                  {saveMutation.isPending ? (
                    <>
                      <div className="w-4 h-4 border-2 border-black/30 border-t-black rounded-full animate-spin" />
                      Saving...
                    </>
                  ) : (
                    <>
                      <CheckCircle size={16} />
                      Save Venue
                    </>
                  )}
                </button>
              </div>
              </form>
            </FormProvider>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "@tanstack/react-router";
import { useRichEditor } from "./editor/useRichEditor";
import RichEditorToolbar from "./editor/RichEditorToolbar";
import { docSchema } from "@shared/schemas/docSchema";
import { useGetAdminDocDetail, useSaveDoc, useDeleteDoc } from "../api";
import { useModal } from "../contexts/ModalContext";
import EditorFooter from "./editor/EditorFooter";
import { useForm } from "@tanstack/react-form";
import { RefreshCw } from "lucide-react";
import { z } from "zod";

type DocFormValues = z.infer<typeof docSchema>;

interface DocData {
  slug: string;
  title: string;
  category: string;
  sortOrder: number;
  description: string;
  isPortfolio: number;
  isExecutiveSummary: number;
  displayInAreslib?: number;
  displayInMathCorner?: number;
  displayInScienceCorner?: number;
  content: string;
  zulipStream?: string;
  zulipTopic?: string;
}

import { CollaborativeEditorRoom, useCollaborativeEditor } from "./editor/CollaborativeEditorRoom";
import VersionHistorySidebar from "./editor/VersionHistorySidebar";
import { CopilotMenu } from "./editor/CopilotMenu";
import ZulipThread from "./ZulipThread";

function DocsEditorInner({ editSlug, userRole, roomId }: { editSlug?: string, userRole?: string | unknown, roomId?: string | null }) {
  const navigate = useNavigate();
  const modal = useModal();
  const [errorMsg, setErrorMsg] = useState("");
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  const { ydoc, provider } = useCollaborativeEditor();
  const editor = useRichEditor({
    placeholder: "<p>Start writing documentation here...</p>",
    ydoc,
    provider
  });

  const form = useForm<DocFormValues>({
    defaultValues: {
      slug: "",
      title: "",
      category: "Getting Started",
      sortOrder: 10,
      description: "",
      isPortfolio: false,
      isExecutiveSummary: false,
      isDraft: false,
      displayInAreslib: true,
      displayInMathCorner: false,
      displayInScienceCorner: false,
      content: "{}"
    }
  });


  const formTitle = form.useStore((s) => s.values.title);

  const { data: docRes, isLoading, isError } = useGetAdminDocDetail(editSlug || "");

  useEffect(() => {
    if (docRes?.doc) {
      const doc = docRes.doc as unknown as DocData;
      form.setFieldValue("slug", doc.slug || "");
      form.setFieldValue("title", doc.title || "");
      form.setFieldValue("category", doc.category || "Getting Started");
      form.setFieldValue("sortOrder", doc.sortOrder || 10);
      form.setFieldValue("description", doc.description || "");
      form.setFieldValue("isPortfolio", !!doc.isPortfolio);
      form.setFieldValue("isExecutiveSummary", !!doc.isExecutiveSummary);
      form.setFieldValue("displayInAreslib", doc.displayInAreslib === undefined ? true : !!doc.displayInAreslib);
      form.setFieldValue("displayInMathCorner", !!doc.displayInMathCorner);
      form.setFieldValue("displayInScienceCorner", !!doc.displayInScienceCorner);
      form.setFieldValue("content", doc.content || "{}");

      if (editor && doc.content) {
        // In collaborative mode, avoid overwriting active live edits with the static DB snapshot.
        // We only inject the DB snapshot if the YDoc is currently empty (e.g. first user joining a new session).
        const shouldSetContent = !ydoc || ydoc.getXmlFragment("default").length === 0;

        if (shouldSetContent) {
          try {
            editor.commands.setContent(JSON.parse(doc.content));
          } catch {
            editor.commands.setContent(doc.content);
          }
        }
      }
    }
  }, [docRes, form, editor, ydoc]);

  const saveMutation = useSaveDoc({
    onSuccess: (res) => {
      if (res.slug) {
        if (form.state.values.isDraft || userRole === "author") {
          navigate({ to: "/dashboard" });
        } else {
          navigate({ to: `/docs/${res.slug}` });
        }
      } else {
        setErrorMsg("Failed to publish");
      }
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Network error");
    }
  });

  const deleteMutation = useDeleteDoc({
    onSuccess: () => {
      navigate({ to: "/dashboard/manage_docs" });
    },
    onError: () => {
      setErrorMsg("Failed to delete the document.");
    }
  });

  const onFormSubmit = (isDraft = false) => {
    if (!editor) return;
    const content = JSON.stringify(editor.getJSON());
    const formValue = form.state.values;
    saveMutation.mutate({ ...formValue, content, isDraft });
  };

  const handleDelete = async () => {
    if (!editSlug) return;
    const confirmed = await modal.confirm({
      title: "Delete Documentation",
      description: "Are you sure you want to permanently delete this documentation page?",
      confirmText: "Delete",
      destructive: true,
    });
    if (!confirmed) return;

    deleteMutation.mutate(editSlug);
  };

  if (isLoading) return <div className="flex items-center justify-center py-20"><RefreshCw className="animate-spin text-ares-red" size={32} /></div>;

  return (

    <div className="flex flex-col gap-6 w-full relative h-full">
        <div className="flex flex-col gap-6 flex-1 min-w-0">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight mb-2">
            {editSlug ? "Edit Document" : "Publish Document"}
          </h2>
          <p className="text-white/50 text-sm">
            {editSlug ? "Modify an existing ARESLib documentation page." : "Draft a new Markdown/Tiptap documentation page for the hub."}
          </p>
        </div>

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          COMMUNICATION FAULT: Failed to retrieve record from server.
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 mt-2">
        <div className="col-span-1 lg:col-span-2">
          <label htmlFor="doc-title" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Title</label>
          <form.Field
            name="title"
            children={(field) => (
              <>
                <input
                  id="doc-title" type="text"
                  name={field.name}
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
                  placeholder="e.g. Swerve Kinematics"
                />
                {field.state.meta.errors.length > 0 && (
                  <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                )}
              </>
            )}
          />
        </div>

        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-slug" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Slug</label>
          <form.Field
            name="slug"
            children={(field) => (
              <>
                <input
                  id="doc-slug" type="text"
                  name={field.name}
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                  disabled={!!editSlug}
                  className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  placeholder="e.g. swerve-kinematics"
                />
                {field.state.meta.errors.length > 0 && (
                  <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                )}
              </>
            )}
          />
        </div>

        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-category" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Category</label>
          <form.Field
            name="category"
            children={(field) => (
              <input
                id="doc-category" type="text"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value)}
                className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
                placeholder="e.g. Tutorials"
              />
            )}
          />
        </div>

        <div className="col-span-1 lg:col-span-1">
          <label htmlFor="doc-sort" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Sort Order</label>
          <form.Field
            name="sortOrder"
            children={(field) => (
              <input
                id="doc-sort" type="number"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(Number(e.target.value))}
                className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
              />
            )}
          />
        </div>
      </div>

      <div>
        <label htmlFor="doc-description" className="block text-xs font-bold text-ares-gold uppercase tracking-wider mb-2">Description / Summary</label>
        <form.Field
          name="description"
          children={(field) => (
            <input
              id="doc-description" type="text"
              name={field.name}
              value={field.state.value}
              onBlur={field.handleBlur}
              onChange={(e) => field.handleChange(e.target.value)}
              className="w-full bg-black/50 border border-white/10 text-white px-4 py-3 ares-cut-sm focus:outline-none focus:ring-2 focus:ring-ares-cyan transition-colors"
