          />
        </div>
      </div>

      {/* ===== Unified Rich Editor ===== */}
      <div className="flex-1 flex flex-col relative min-h-[500px]">
        {editor && (
          <>
            <div className="flex items-center gap-2">
              <div className="flex-1"><RichEditorToolbar editor={editor} documentTitle={formTitle || ""} /></div>
            </div>
