  const { ydoc, provider } = useCollaborativeEditor();
  const editor = useRichEditor({ 
    placeholder: "<p>Describe your upcoming event or write a full recap here...</p>",
    ydoc,
    provider,
    yfield: 'default'
  });


  const { availableSocials } = useAdminSettings();
  const { uploadFile, isUploading, setErrorMsg: setUploadError } = useImageUpload();

  const [isDeleted, setIsDeleted] = useState(false);
  const [isException, setIsException] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");
  const [isCoverPickerOpen, setIsCoverPickerOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isLocationModalOpen, setIsLocationModalOpen] = useState(false);

  const form = useForm<EventPayload>({
    defaultValues: {
      title: "",
      dateStart: "",
      dateEnd: "",
      location: "",
      description: "",
      coverImage: DEFAULT_coverImage,
      category: "internal",
      tbaEventKey: "",
      isPotluck: false,
      isVolunteer: false,
      publishedAt: "",
      seasonId: undefined,
      meetingNotes: "",
      socials: {
        discord: true,
        bluesky: true,
        slack: false,
        teams: false,
        gchat: false,
        facebook: false,
        twitter: false,
        instagram: false
      },
      rrule: ""
    }
  });



  const [recurringGroupId, setRecurringGroupId] = useState<string | null>(null);
  const [updateMode, setUpdateMode] = useState<"single" | "following">("single");

  const [rruleFreq, setRruleFreq] = useState("");
  const [limitType, setLimitType] = useState<"none" | "count" | "date">("none");
  const [limitCount, setLimitCount] = useState("");
  const [limitDate, setLimitDate] = useState("");

  const { data: locations = [] } = useQuery<Location[]>({
    queryKey: ["locations"],
    queryFn: async () => {
      try {
        const res = await fetch("/api/locations");
        if (res.ok) {
          const data = (await res.json()) as { locations?: Location[] };
          return data.locations || [];
        }
        return [];
      } catch {
        return [];
      }
    }
  });

  // Use Hono client query for admin event detail
  const { data: eventRes, isLoading, isError } = useGetAdminEventDetail(editId || "", {
    enabled: !!editId
  });

  useEffect(() => {
    let active = true;
    const processEventData = async () => {
      await Promise.resolve();
      if (!active) return;

      if (eventRes?.event) {
        const event = eventRes.event;
        const formatForInput = (d: string | null | undefined) => {
          if (!d) return "";
          if (d.length === 10) return d + "T00:00";
          return d.slice(0, 16).replace(" ", "T");
        };

        setIsDeleted(event.isDeleted === 1);
        setIsException(event.recurringException === 1);
        form.setFieldValue("title", event.title || "");
        form.setFieldValue("dateStart", formatForInput(event.dateStart));
        form.setFieldValue("dateEnd", formatForInput(event.dateEnd));
        form.setFieldValue("location", event.location || "");
        form.setFieldValue("description", event.description || "");
        form.setFieldValue("coverImage", event.coverImage || DEFAULT_coverImage);
        form.setFieldValue("category", (event.category || "internal") as "internal" | "outreach" | "external");
        form.setFieldValue("tbaEventKey", event.tbaEventKey || "");
        form.setFieldValue("isPotluck", event.isPotluck === 1);
        form.setFieldValue("isVolunteer", event.isVolunteer === 1);
        form.setFieldValue("publishedAt", ((event as unknown) as Record<string, unknown>).publishedAt as string || "");
        form.setFieldValue("seasonId", event.seasonId ? Number(event.seasonId) : undefined);
        form.setFieldValue("socials", ((eventRes as unknown) as Record<string, unknown>).socials as Record<string, boolean> || {});

        // Parse rrule
        let parsedFreq = "";
        let parsedLimitType: "none" | "count" | "date" = "none";
        let parsedLimitCount = "";
        let parsedLimitDate = "";

        if (event.rrule) {
          const parts = event.rrule.split(';');
          parts.forEach((p: string) => {
            if (p.startsWith('FREQ=')) parsedFreq = p;
            else if (p.startsWith('COUNT=')) { parsedLimitType = "count"; parsedLimitCount = p.substring(6); }
            else if (p.startsWith('UNTIL=')) { 
              parsedLimitType = "date"; 
              const dStr = p.substring(6); 
              if (dStr.length >= 8) parsedLimitDate = `${dStr.substring(0,4)}-${dStr.substring(4,6)}-${dStr.substring(6,8)}`;
            }
          });
        }
        setRruleFreq(parsedFreq);
        setLimitType(parsedLimitType);
        setLimitCount(parsedLimitCount);
        setLimitDate(parsedLimitDate);

        setRecurringGroupId(event.recurringGroupId || null);

        if (editor) {
          const shouldSetContent = !ydoc || ydoc.getXmlFragment("default").length === 0;
          if (shouldSetContent && event.description) {
            try {
              editor.commands.setContent(JSON.parse(event.description));
            } catch {
              editor.commands.setContent(`<p>${event.description}</p>`);
            }
          }
        }
      }
    };

    void processEventData();
    return () => { active = false; };

  }, [eventRes, form, editor, ydoc]);


  const saveMutation = useSaveEvent({
    onSuccess: (data: Record<string, unknown>) => {
      if (data.success) {
        toast.success("Event published!");
        if (data.warning) toast.info(data.warning as string);
        navigate({ to: "/dashboard" });
      } else {
        setErrorMsg("Event save failed.");
      }
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Network error.");
    }
  });

  const updateMutation = useUpdateEvent({
    onSuccess: (data: Record<string, unknown>) => {
      if (data.success) {
        toast.success("Event updated!");
        if (data.warning) toast.info(data.warning as string);
        navigate({ to: "/dashboard" });
      } else {
        setErrorMsg((data.error as string) || "Event update failed.");
      }
    },
    onError: (err: Error) => {
      setErrorMsg(err.message || "Network error.");
    }
  });

  const deleteMutation = useDeleteEvent({
    onSuccess: () => {
      navigate({ to: "/dashboard/manage_event" });
    },
    onError: () => {
      setErrorMsg("Failed to delete the event.");
    }
  });

  const onFormSubmit = (isDraft = false) => {
    let finalRrule = rruleFreq;
    if (finalRrule && limitType === 'count' && limitCount) {
      finalRrule += `;COUNT=${limitCount}`;
    } else if (finalRrule && limitType === 'date' && limitDate) {
      finalRrule += `;UNTIL=${limitDate.replace(/-/g, '')}T000000Z`;
    }

    const formValue = form.state.values;
    const finalDescription = editor ? JSON.stringify(editor.getJSON()) : formValue.description;
    const payload = { ...formValue, description: finalDescription, meetingNotes: "", isDraft, updateMode, rrule: finalRrule };
    if (editId) {
      updateMutation.mutate({ id: editId, body: payload });
    } else {
      saveMutation.mutate(payload);
    }
  };

  const handleDelete = async () => {
    if (!editId) return;

    let deleteMode: "single" | "following" = "single";
    if (recurringGroupId) {
      const confirmFollowing = await modal.confirm({
        title: "Delete Recurring Event",
        description: "This is a recurring event. Do you want to delete all following events in the series too?",
        confirmText: "Delete Following",
        cancelText: "Only This Event"
      });
      if (confirmFollowing) deleteMode = "following";
    } else {
      const confirmed = await modal.confirm({
        title: "Delete Event",
        description: "Are you sure you want to permanently delete this event?",
        confirmText: "Delete",
        destructive: true,
      });
      if (!confirmed) return;
    }

    deleteMutation.mutate({ id: editId, deleteMode });
  };

  const handleFileUpload = async (file: File) => {
    try {
      setUploadError("");
      const { url } = await uploadFile(file);
      form.setFieldValue("coverImage", url);
    } catch(err) {
      setErrorMsg(String(err));
    }
  };

  if (isLoading) return <div className="flex items-center justify-center py-20"><RefreshCw className="animate-spin text-ares-red" size={32} /></div>;

  return (

      <div className="flex flex-col gap-6 w-full relative h-full">
        <div>
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight mb-2">
            {editId ? "Edit Event" : "Publish Event"}
          </h2>
          <p className="text-white/60 text-sm">
            {editId ? "Update existing competition or outreach details." : "Add upcoming competitions or outreach events to the portal."}
          </p>
        </div>

      {isError && (
        <div className="bg-ares-red/10 border border-ares-red/30 p-4 ares-cut-sm text-ares-red text-xs font-bold mb-6 flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-ares-red animate-pulse" />
          COMMUNICATION FAULT: Failed to retrieve record from server.
        </div>
      )}

      {isDeleted && (
        <div className="bg-ares-danger/10 border-l-4 border-ares-danger p-4 mb-6 flex items-start gap-3">
          <div className="text-ares-danger mt-0.5">âš ï¸</div>
          <div>
            <h4 className="text-white font-bold text-sm tracking-wide uppercase">Ghost Event</h4>
            <p className="text-white text-sm mt-1 font-bold">This event is currently soft-deleted and is hidden from the public API and Google Calendar.</p>
          </div>
        </div>
      )}

      {isException && (
        <div className="bg-ares-gold/10 border-l-4 border-ares-gold p-4 mb-6 flex items-start gap-3">
          <div className="text-ares-gold mt-0.5">â„¹ï¸</div>
          <div>
            <h4 className="text-white font-bold text-sm tracking-wide uppercase">Exception Instance</h4>
            <p className="text-white/80 text-sm mt-1 font-bold">This is a modified instance of a recurring series. Changes will only apply to this specific event.</p>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row gap-4 mt-2">
        <div className="flex-1">
          <label htmlFor="event-title" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Event Title *</label>
          <form.Field
            name="title"
            children={(field) => (
              <>
                <input
                  id="event-title" type="text"
                  name={field.name}
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner"
                  placeholder="State Championship"
                />
                {field.state.meta.errors.length > 0 && (
                  <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                )}
              </>
            )}
          />
        </div>
        <div className="flex-1">
          <CoverAssetPicker
            coverImage={form.useStore(s => s.values.coverImage) || DEFAULT_coverImage}
            isUploading={isUploading}
            onUrlChange={(url) => form.setFieldValue("coverImage", url)}
            onLibraryClick={() => setIsCoverPickerOpen(true)}
            onFileChange={handleFileUpload}
          />
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <label htmlFor="event-category" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Category *</label>
          <form.Field
            name="category"
            children={(field) => (
              <select
                id="event-category"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value as "internal" | "outreach" | "external")}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner appearance-none"
              >
                <option value="internal">ARES Practices</option>
                <option value="outreach">ARES Outreach &amp; Volunteer</option>
                <option value="external">ARES Community Spotlight</option>
              </select>
            )}
          />
        </div>
        <div className="flex-1">
          <label htmlFor="event-tba-key" className="text-xs font-bold text-white/60 uppercase tracking-wider mb-2 flex items-center justify-between">
            <span>TBA Event Key</span>
            <span className="text-xs text-white/60 font-normal normal-case">Optional</span>
          </label>
          <form.Field
            name="tbaEventKey"
            children={(field) => (
              <input
                id="event-tba-key" type="text"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value)}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner"
                placeholder="e.g. 2024wvcmp"
              />
            )}
          />
        </div>
        <div className="flex-1">
          <form.Field
            name="seasonId"
            children={(field) => (
              <SeasonPicker value={field.state.value || ""} onChange={(val) => field.handleChange(val ? Number(val) : undefined)} />
            )}
          />
        </div>
        <div className="flex-1">
          <label htmlFor="event-location" className="text-xs font-bold text-white/60 uppercase tracking-wider mb-2 flex items-center justify-between">
            <span>Location</span>
            <span className="text-xs text-white/60 font-normal normal-case">Pick from registry</span>
          </label>
          <div className="relative group">
            <form.Field
              name="location"
              children={(field) => (
                <LocationCombobox
                  id="event-location"
                  locations={locations}
                  value={field.state.value || ''}
                  onChange={(val) => field.handleChange(val)}
                  onCustomClick={() => setIsLocationModalOpen(true)}
                />
              )}
            />
          </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4">
        <div className="flex-1">
          <label htmlFor="event-start" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Start Date & Time *</label>
          <form.Field
            name="dateStart"
            children={(field) => (
              <>
                <input
                  id="event-start" type="datetime-local"
                  name={field.name}
                  value={field.state.value}
                  onBlur={field.handleBlur}
                  onChange={(e) => field.handleChange(e.target.value)}
                  className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
                />
                {field.state.meta.errors.length > 0 && (
                  <p className="text-[10px] font-black uppercase text-ares-red mt-1">{field.state.meta.errors[0]}</p>
                )}
              </>
            )}
          />
        </div>
        <div className="flex-1">
          <label htmlFor="event-end" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">End Date & Time</label>
          <form.Field
            name="dateEnd"
            children={(field) => (
              <input
                id="event-end" type="datetime-local"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value)}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
              />
            )}
          />
        </div>
        <div className="flex-1">
          <label htmlFor="event-published-at" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Schedule Publish Time</label>
          <form.Field
            name="publishedAt"
            children={(field) => (
              <input
                id="event-published-at" type="datetime-local"
                name={field.name}
                value={field.state.value}
                onBlur={field.handleBlur}
                onChange={(e) => field.handleChange(e.target.value)}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
              />
            )}
          />
        </div>
      </div>

      {!isException && (
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label htmlFor="event-rrule" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Repeats</label>
            <select
              id="event-rrule"
              value={rruleFreq}
              onChange={(e) => {
                setRruleFreq(e.target.value);
                if (!e.target.value) {
                  setLimitType("none");
                  setLimitCount("");
                  setLimitDate("");
                }
              }}
              className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner appearance-none"
            >
              <option value="">Never</option>
              <option value="FREQ=DAILY">Daily</option>
              <option value="FREQ=WEEKLY">Weekly</option>
              <option value="FREQ=MONTHLY">Monthly</option>
            </select>
          </div>
        </div>
      )}

      {!isException && rruleFreq && (
        <div className="flex flex-col md:flex-row gap-4 p-4 border border-white/10 bg-black/20 ares-cut-sm mb-4">
          <div className="flex-1">
            <label htmlFor="limitType" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Recurrence Limit</label>
            <select
              id="limitType"
              value={limitType}
              onChange={(e) => setLimitType(e.target.value as "none" | "count" | "date")}
              className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner appearance-none"
            >
              <option value="none">Forever (Max 52 instances)</option>
              <option value="count">End after X occurrences</option>
              <option value="date">End by specific date</option>
            </select>
          </div>

          {limitType === 'count' && (
            <div className="flex-1">
              <label htmlFor="limitCount" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Number of Occurrences</label>
              <input
                id="limitCount"
                type="number"
                min="1"
                max="52"
                value={limitCount}
                onChange={(e) => setLimitCount(e.target.value)}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner"
                placeholder="e.g. 10"
              />
            </div>
          )}

          {limitType === 'date' && (
            <div className="flex-1">
              <label htmlFor="limitDate" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">End Date</label>
              <input
                id="limitDate"
                type="date"
                value={limitDate}
                onChange={(e) => setLimitDate(e.target.value)}
                className="w-full bg-obsidian border border-white/10 ares-cut-sm px-4 py-3 text-white placeholder-white/60 focus:border-ares-red focus:outline-none focus:ring-1 focus:ring-ares-red transition-all shadow-inner [&::-webkit-calendar-picker-indicator]:invert"
              />
            </div>
          )}
        </div>
      )}

      <EventPotluckVolunteerFlags
        isPotluck={form.useStore(s => s.values.isPotluck) || false}
        isVolunteer={form.useStore(s => s.values.isVolunteer) || false}
        onChange={(field, val) => form.setFieldValue(field as "isPotluck" | "isVolunteer", val as boolean)}
      />

      <div>
        <label htmlFor="event-desc-editor" className="block text-xs font-bold text-white/60 uppercase tracking-wider mb-2">Event Description / Recap</label>
        {editor && (
          <div className="flex items-center gap-2">
            <div className="flex-1"><RichEditorToolbar editor={editor} documentTitle={form.useStore(s => s.values.title) || ""} /></div>
          </div>
        )}
        {editor && <CopilotMenu editor={editor} />}
      </div>

      {editId && form.useStore(s => s.values.title) && (
        <ZulipThread stream="events" topic={`Event: ${form.useStore(s => s.values.title)}`} />
      )}

      <div className="mt-6 flex flex-col gap-4">
        {errorMsg && (
          <div className="p-4 bg-ares-danger/10 border border-ares-danger/20 ares-cut flex items-start gap-3">
            <div className="text-ares-danger mt-0.5">âš ï¸</div>
            <div>
              <h4 className="text-white font-bold text-xs tracking-wide uppercase">Critical Error</h4>
              <p id="event-error-msg" className="text-white text-sm mt-1 font-bold">{errorMsg}</p>
            </div>
          </div>
        )}

        {recurringGroupId && editId && !isException && (
          <div className="p-4 bg-obsidian border border-white/10 ares-cut flex items-center justify-between gap-4">
            <div>
              <h4 className="text-white font-bold text-sm tracking-wide">Recurring Event Options</h4>
              <p className="text-white/60 text-xs mt-1">This event is part of a series. Choose how your updates will be applied.</p>
            </div>
            <select
              value={updateMode}
              onChange={(e) => setUpdateMode(e.target.value as "single" | "following")}
              className="bg-black border border-white/20 ares-cut-sm px-4 py-2 text-white text-sm focus:border-ares-red focus:outline-none transition-all shadow-inner"
            >
              <option value="single">Only this instance</option>
              <option value="following">This and all following instances</option>
            </select>
          </div>
        )}

        <EditorFooter
          errorMsg={errorMsg}
          isPending={saveMutation.isPending}
          isEditing={!!editId}
          onDelete={handleDelete}
          onSaveDraft={() => onFormSubmit(true)}
          onPublish={() => onFormSubmit(false)}
          deleteText="DELETE"
          updateText="UPDATE EVENT"
          publishText={userRole === "author" ? "SUBMIT FOR REVIEW" : "PUBLISH EVENT"}
          userRole={userRole}
          roundedClass="ares-cut"
          onShowHistory={() => setIsHistoryOpen(true)}
          extraControls={
            <SocialSyndicationGrid
              availableSocials={availableSocials}
              socials={form.useStore(s => s.values.socials) as Record<string, boolean>}
              onChange={(platform, val) => form.setFieldValue(`socials.${platform}`, val)}
              isEdit={!!editId}
            />
          }
        />
      </div>

      <AssetPickerModal
        isOpen={isCoverPickerOpen}
        onClose={() => setIsCoverPickerOpen(false)}
        onSelect={(url) => {
          form.setFieldValue("coverImage", url);
          setIsCoverPickerOpen(false);
        }}
      />

      <CreateLocationModal
        isOpen={isLocationModalOpen}
        onClose={() => {
          setIsLocationModalOpen(false);
          // If they close without saving, reset dropdown to empty
          if (form.useStore(s => s.values.location) === "CUSTOM") {
            form.setFieldValue("location", "");
          }
        }}
        onSuccess={(newName) => {
          setIsLocationModalOpen(false);
          // Add temporary option so it is immediately selectable before query refetch
          const selectEl = document.getElementById('event-location');
          if (selectEl instanceof HTMLSelectElement && !Array.from(selectEl.options).some(opt => opt.value === newName)) {
            const tempOpt = new Option(newName, newName);
            selectEl.add(tempOpt, selectEl.options[selectEl.options.length - 1]);
          }
          form.setFieldValue("location", newName);
        }}
      />

      {isHistoryOpen && editId && editor && (
        <VersionHistorySidebar
          roomId={`event_${editId}`}
          editor={editor}
          onClose={() => setIsHistoryOpen(false)}
          historyUrl={`/api/events/admin/${editId}/history`}
        />
      )}
      </div>
    </div>
  );
}

export default function EventEditor({ userRole }: { userRole?: string | unknown }) {
  const { editId } = useParams({ strict: false }) as Record<string, string>;

  const [draftId] = useState(() => `draft_event_${crypto.randomUUID?.() || Math.random().toString(36).substring(2)}`);
  const roomId = editId ? `event_${editId}` : draftId;

  return (
    <CollaborativeEditorRoom roomId={roomId}>
      <EventEditorInner editId={editId} userRole={userRole} roomId={roomId} />
    </CollaborativeEditorRoom>
  );
}

import { useState, useEffect, useMemo } from "react";
import { ClipboardList, Plus, Save, RefreshCw, Trash2, CheckCircle2, Circle, AlertCircle, Users } from "lucide-react";
import { useGetEventSignups, useSubmitEventSignup, useDeleteMyEventSignup, useUpdateMyEventAttendance, useUpdateUserEventAttendance, type EventSignup } from "../api/events";
import { useForm } from "@tanstack/react-form";
import { z } from "zod";
import { zodValidator } from "@tanstack/zod-form-adapter";

const eventSignupSchema = z.object({
	bringing: z.string().optional(),
	notes: z.string().optional(),
	prep_hours: z.number().min(0).optional(),
});

interface EventSignupsProps {
	eventId: string;
	isPotluck: boolean;
	isVolunteer?: boolean;
}

export default function EventSignups({ eventId, isPotluck, isVolunteer }: EventSignupsProps) {
	const [signupError, setSignupError] = useState<string | null>(null);

	const { data: signupsData, isLoading } = useGetEventSignups(eventId);
	const submitSignup = useSubmitEventSignup();
	const deleteSignup = useDeleteMyEventSignup();
	const updateMyAttendance = useUpdateMyEventAttendance();
	const updateUserAttendance = useUpdateUserEventAttendance();

	const signups = useMemo(() => signupsData?.signups || [], [signupsData?.signups]);
	const isAuthenticated = signupsData?.authenticated || false;
	const userRole = signupsData?.role || "unverified";
	const canManage = signupsData?.can_manage || false;
	const dietarySummary = signupsData?.dietary_summary || null;
	const teamDietarySummary = signupsData?.team_dietary_summary || null;

	const form = useForm({
		defaultValues: {
			bringing: "",
			notes: "",
			prep_hours: 0,
		},
		onSubmit: async ({ value }) => {
			setSignupError(null);
			try {
				await submitSignup.mutateAsync({ eventId, body: value });
			} catch (e) {
				console.error("[RSVP Error]", e);
				setSignupError(e instanceof Error ? e.message : "Failed to RSVP. Please try again.");
			}
		},
	});

	const { Provider: FormProvider } = form;

	// Initialize form with existing signup data
	useEffect(() => {
		const own = signups.find((s: EventSignup) => s.is_own);
		if (own) {
			form.setFieldValue("bringing", own.bringing || "");
			form.setFieldValue("notes", own.notes || "");
			form.setFieldValue("prep_hours", own.prep_hours || 0);
		}
	}, [signups, form]);

	const handleRemove = async () => {
		setSignupError(null);
		try {
			await deleteSignup.mutateAsync(eventId);
			form.reset();
		} catch (e) {
			console.error("[Remove RSVP Error]", e);
			setSignupError(e instanceof Error ? e.message : "Failed to remove RSVP. Please try again.");
		}
	};

	const toggleAttendance = async (userId: string, currentStatus: number | undefined) => {
		try {
			await updateUserAttendance.mutateAsync({
				eventId,
				userId,
				attended: !currentStatus
			});
		} catch (e) {
			console.error("[Toggle Attendance Error]", e);
		}
	};

	const selfCheckIn = async () => {
		setSignupError(null);
		const myEntry = signups.find(s => s.is_own);
		const isCurrentlyAttended = !!myEntry?.attended;
		try {
			await updateMyAttendance.mutateAsync({
				eventId,
				attended: !isCurrentlyAttended
			});
		} catch (e) {
			console.error("[Check-in Error]", e);
			setSignupError(e instanceof Error ? e.message : "Failed to update attendance. Please try again.");
		}
	};

	if (isLoading) return null;

	const myEntry = signups.find(s => s.is_own);
	const totalAttending = signups.filter(s => !!s.attended).length;
	const totalPrep = signups.reduce((sum, s) => sum + (s.prep_hours || 0), 0);
	const hasExistingSignup = !!myEntry;

	return (
		<div className="mt-10 border-t border-white/10 pt-8 space-y-8">
			{/* Attendance & Provisions Summary (Visible to verified users) */}
			<div className="grid grid-cols-1 md:grid-cols-2 gap-4">
				<div className="bg-obsidian/40 border border-white/10 p-5 ares-cut">
					<h4 className="text-marble/60 text-xs font-black uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
						<Users size={14} className="text-ares-gold" /> Attendance Stats
					</h4>
					<div className="flex items-baseline gap-2">
						<span className="text-3xl font-black text-white">{totalAttending}</span>
						<span className="text-marble/60 text-sm font-bold">/ {signups.length} present</span>
					</div>
					{isVolunteer && (
						<div className="mt-4 pt-4 border-t border-white/10 flex justify-between items-center text-sm font-bold">
							<span className="text-marble/60 uppercase tracking-widest text-xs">Volunteer Prep Time</span>
							<span className="text-ares-gold">{totalPrep} hrs</span>
						</div>
					)}
				</div>

				{dietarySummary && (
					<div className="bg-obsidian/40 border border-white/10 p-5 ares-cut">
						<h4 className="text-marble/60 text-xs font-black uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
							<AlertCircle size={14} className="text-ares-red" /> Dietary Restrictions
						</h4>
						<div className="flex flex-col gap-4">
							<div>
								<span className="text-xs text-white/50 block mb-2 font-bold uppercase tracking-widest">RSVP&apos;d Members</span>
								<div className="flex flex-wrap gap-2">
									{Object.entries(dietarySummary).length > 0 ? (
										Object.entries(dietarySummary).map(([restriction, count]) => (
											<span key={`rsvp-${restriction}`} className="px-2 py-1 bg-ares-red/10 border border-ares-red/20 ares-cut-sm text-xs font-bold text-ares-red">
												{count} {restriction}
											</span>
										))
									) : (
										<span className="text-marble/30 text-xs font-medium leading-relaxed">No dietary restrictions among RSVPs.</span>
									)}
								</div>
							</div>

							{teamDietarySummary && Object.entries(teamDietarySummary).length > 0 && (
								<div>
									<span className="text-xs text-white/50 block mb-2 font-bold uppercase tracking-widest">Entire Team Roster</span>
									<div className="flex flex-wrap gap-2 opacity-70 grayscale">
										{Object.entries(teamDietarySummary).map(([restriction, count]) => (
											<span key={`team-${restriction}`} className="px-2 py-1 bg-white/10 border border-white/20 ares-cut-sm text-xs font-bold text-marble">
												{count} {restriction}
											</span>
										))}
									</div>
								</div>
							)}
						</div>
					</div>
				)}
			</div>

			{isAuthenticated && userRole !== "unverified" ? (
				<>
					<div>
						<div className="flex items-center justify-between mb-6">
							<h3 className="text-lg font-black flex items-center gap-2">
								<ClipboardList size={20} className="text-ares-gold" />
								RSVPs & Sign-Ups ({signups.length})
							</h3>

							{/* Self Check-in Button */}
							<button
								onClick={selfCheckIn}
								className={`flex items-center gap-2 px-4 py-2 ares-cut-sm text-xs font-black uppercase tracking-widest transition-all ${
									myEntry?.attended
									? "bg-ares-gold/10 border border-ares-gold/20 text-ares-gold hover:bg-ares-gold/20"
									: "bg-ares-gold hover:brightness-110 text-black shadow-lg shadow-ares-gold/20"
								}`}
							>
								<CheckCircle2 size={14} />
								{myEntry?.attended ? "Checked In (Undo)" : "Check In Now"}
							</button>
						</div>

						{/* Table */}
						<div className="overflow-x-auto mb-6 bg-obsidian/20 border border-white/10 ares-cut">
							<table className="w-full">
								<thead>
									<tr className="border-b border-white/10 text-xs font-bold text-marble/60 uppercase tracking-wider">
										<th className="text-left py-3 px-4">Status</th>
										<th className="text-left py-3 px-4">Who</th>
										{isPotluck && <th className="text-left py-3 px-4">Bringing</th>}
										{isVolunteer && <th className="text-left py-3 px-4">Prep Hrs</th>}
										<th className="text-left py-3 px-4">Notes</th>
									</tr>
								</thead>
								<tbody>
									{signups.map(entry => (
										<tr key={entry.user_id} className={`border-b border-white/10 transition-colors ${entry.attended ? "bg-ares-gold/5" : ""}`}>
											<td className="py-3 px-4">
												{canManage ? (
													<button
														onClick={() => toggleAttendance(entry.user_id, entry.attended)}
														className={`transition-colors ${entry.attended ? "text-ares-gold" : "text-marble/10 hover:text-marble/30"}`}
													>
														{entry.attended ? <CheckCircle2 size={18} /> : <Circle size={18} />}
													</button>
												) : (
													<div className={entry.attended ? "text-ares-gold" : "text-marble/5"}>
														{entry.attended ? <CheckCircle2 size={18} /> : <Circle size={18} />}
													</div>
												)}
											</td>
											<td className="py-3 px-4">
												<div className="flex items-center gap-2">
													<img src={`https://api.dicebear.com/9.x/bottts/svg?seed=${entry.user_id}`}
														alt={`${entry.nickname || "ARES Member"}'s avatar`} className="w-6 h-6 ares-cut-sm bg-white/10" />
													<span className={`text-sm font-bold ${entry.attended ? "text-white" : "text-marble/60"}`}>{entry.nickname || "ARES Member"}</span>
												</div>
											</td>
											{isPotluck && <td className="py-3 px-4 text-sm text-marble">{entry.bringing || "—"}</td>}
											{isVolunteer && <td className="py-3 px-4 text-sm text-marble">{entry.prep_hours || 0}</td>}
											<td className="py-3 px-4 text-sm text-marble/60">{entry.notes || "—"}</td>
										</tr>
									))}
									{signups.length === 0 && (
										<tr><td colSpan={5} className="py-12 text-center text-marble/30 text-sm">No RSVPs yet. Be the first!</td></tr>
									)}
								</tbody>
							</table>
						</div>
					</div>

					{/* Sign Up Form */}
					<div className="bg-obsidian/50 border border-white/10 ares-cut-lg p-6 space-y-4">
						<div className="flex items-center justify-between">
							<p className="text-xs font-black text-ares-gold uppercase tracking-[0.2em]">
								{hasExistingSignup ? "Update Your RSVP" : "RSVP to this Event"}
							</p>
							<span className="text-xs text-marble/20 font-bold uppercase tracking-widest">ARES Event Protocol v3.0</span>
						</div>

						{/* Error display */}
						{signupError && (
							<div className="bg-ares-red/10 border border-ares-red/30 p-3 ares-cut-sm">
								<p className="text-xs text-ares-red font-bold flex items-center gap-2">
									<AlertCircle size={14} />
									{signupError}
								</p>
							</div>
						)}

						<FormProvider>
							<form
								onSubmit={(e) => {
									e.preventDefault();
									e.stopPropagation();
									form.handleSubmit();
								}}
								className="space-y-4"
							>
								<div className="grid grid-cols-1 md:grid-cols-2 gap-4">
									{isPotluck && (
										<form.Field
											name="bringing"
											children={(field) => (
												<input
													name={field.name}
													value={field.state.value}
													onBlur={field.handleBlur}
													onChange={(e) => field.handleChange(e.target.value)}
													placeholder="What are you bringing? (e.g. chips & salsa)"
													className="w-full bg-white/5 border border-white/10 ares-cut-sm px-4 py-3 text-sm text-white placeholder-marble/40 focus:outline-none focus:border-ares-gold focus:ring-1 focus:ring-ares-gold/20 transition-all"
												/>
											)}
										/>
									)}
									<form.Field
										name="notes"
										children={(field) => (
											<input
												name={field.name}
												value={field.state.value}
												onBlur={field.handleBlur}
												onChange={(e) => field.handleChange(e.target.value)}
												placeholder={isPotluck ? "Notes (dietary info, arrival time...)" : "Notes (arrival time, etc...)"}
												className={`w-full ${(isPotluck && isVolunteer) || (!isPotluck && !isVolunteer) ? 'col-span-2' : ''} bg-white/5 border border-white/10 ares-cut-sm px-4 py-3 text-sm text-white placeholder-marble/40 focus:outline-none focus:border-ares-gold focus:ring-1 focus:ring-ares-gold/20 transition-all`}
											/>
										)}
									/>
									{isVolunteer && (
										<form.Field
											name="prep_hours"
											children={(field) => (
												<div className="flex items-center gap-3">
													<span className="text-marble/60 uppercase tracking-widest text-xs font-bold shrink-0">Prep Hrs</span>
													<input
														type="number" step="0.5" min="0" placeholder="0"
														name={field.name}
														value={field.state.value}
														onBlur={field.handleBlur}
														onChange={(e) => field.handleChange(parseFloat(e.target.value) || 0)}
														className="w-full md:w-32 bg-white/5 border border-white/10 ares-cut-sm px-4 py-3 text-sm text-white focus:outline-none focus:border-ares-gold focus:ring-1 focus:ring-ares-gold/20 transition-all"
													/>
												</div>
											)}
										/>
									)}
								</div>
								<div className="flex gap-3">
									<button
										type="submit"
										disabled={submitSignup.isPending}
										className="flex-1 md:flex-none flex items-center justify-center gap-2 px-8 py-3 bg-ares-gold/10 hover:bg-ares-gold/20 border border-ares-gold/30 text-ares-gold ares-cut-sm text-sm font-black uppercase tracking-widest transition-all disabled:opacity-50"
									>
										{submitSignup.isPending ? <RefreshCw size={16} className="animate-spin" /> : hasExistingSignup ? <Save size={16} /> : <Plus size={16} />}
										{hasExistingSignup ? "Update RSVP" : "RSVP Here"}
									</button>
									{hasExistingSignup && (
										<button
											type="button"
											onClick={handleRemove}
											className="flex flex-1 md:flex-none items-center justify-center gap-2 px-6 py-3 bg-ares-danger/10 hover:bg-ares-danger/20 border border-ares-danger/20 text-ares-danger ares-cut-sm text-sm font-black uppercase tracking-widest transition-all"
										>
											<Trash2 size={16} /> Cancel RSVP
										</button>
									)}
								</div>
							</form>
						</FormProvider>
					</div>
				</>
			) : (
				<div className="my-12 p-8 bg-obsidian/50 border border-white/10 ares-cut-lg text-center">
					<p className="text-sm text-marble mb-2">
						<span className="text-ares-gold font-bold">Verified Access Required</span>
					</p>
					<p className="text-sm text-marble/60 max-w-md mx-auto mb-6">
						Sign-ups and provisions are restricted to verified ARES members to protect privacy.
					</p>
					{!isAuthenticated ? (
						<div>
							<a href="/login" className="px-6 py-3 bg-ares-gold hover:brightness-110 ares-cut-sm font-black text-xs uppercase tracking-widest inline-block transition-all shadow-lg shadow-ares-gold/20" style={{ color: '#000' }}>Sign in with ARES ID</a>
							<p className="text-xs uppercase tracking-widest text-marble/20 mt-6 font-bold">
								Don&apos;t have an ARES ID? <a href="/about" className="text-ares-gold hover:underline">Contact us</a>
							</p>
						</div>
					) : (
						<p className="text-xs uppercase tracking-widest text-marble/60 font-bold max-w-sm mx-auto">Your account is pending team administrator verification. If you have any questions, <a href="/about" className="text-ares-gold hover:underline">contact us</a>.</p>
					)}
				</div>
			)}
		</div>
	);
}

import { useState } from "react";
import { z } from "zod";
import DashboardPageHeader from "./dashboard/DashboardPageHeader";
import DashboardMetricsGrid from "./dashboard/DashboardMetricsGrid";
import DashboardEmptyState from "./dashboard/DashboardEmptyState";
import { DashboardInput, DashboardSubmitButton } from "./dashboard/DashboardFormInputs";
import { Plus, Trash2, DollarSign, PieChart, TrendingUp, TrendingDown, RefreshCw, Wallet, Building, Circle, UserPlus, Handshake, CheckCircle2, XCircle as XCircleIcon } from "lucide-react";
import { GenericKanbanBoard, KanbanColumnConfig } from "./kanban/GenericKanbanBoard";
import { SortablePipelineCard } from "./kanban/SortablePipelineCard";
import SponsorshipEditModal from "./kanban/SponsorshipEditModal";
import { motion, AnimatePresence } from "framer-motion";
import SeasonPicker from "./SeasonPicker";
import { toast } from "sonner";
import { useForm } from "@tanstack/react-form";
import { zodValidator } from "@tanstack/zod-form-adapter";
import { financeTransactionSchema, sponsorshipPipelineSchema, type SponsorshipPipelinePayload } from "@shared/schemas/financeSchema";
import type { PipelineItem, TransactionItem } from "../types/finance";
import { 
  useGetFinanceSummary, 
  useListSponsorshipPipeline, 
  useSaveSponsorshipPipeline, 
  useDeleteSponsorshipPipeline, 
  useListFinanceTransactions, 
  useSaveFinanceTransaction, 
  useDeleteFinanceTransaction 
} from "../api";

// â”€â”€ Status config for Sponsorship â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const PIPELINE_COLUMNS = ["potential", "contacted", "pledged", "secured", "lost"] as const;

const pipelineConfig: Record<string, KanbanColumnConfig> = {
  potential: { bg: "bg-white/5", text: "text-marble/50", border: "border-white/10", label: "Potential", icon: Circle },
  contacted: { bg: "bg-ares-cyan/10", text: "text-ares-cyan", border: "border-ares-cyan/30", label: "Contacted", icon: UserPlus },
  pledged:   { bg: "bg-ares-gold/10", text: "text-ares-gold", border: "border-ares-gold/30", label: "Pledged", icon: Handshake },
  secured:   { bg: "bg-ares-green/10", text: "text-ares-green", border: "border-ares-green/30", label: "Secured", icon: CheckCircle2 },
  lost:      { bg: "bg-ares-red/10", text: "text-ares-red", border: "border-ares-red/30", label: "Lost", icon: XCircleIcon },
};

export type { PipelineItem, TransactionItem };

export default function FinanceManager() {
  const [activeTab, setActiveTab] = useState<"pipeline" | "ledger">("pipeline");
  const [isAdding, setIsAdding] = useState(false);
  const [selectedSeason, setSelectedSeason] = useState<number | null>(null);
  const [editingLead, setEditingLead] = useState<PipelineItem | null>(null);
  const [activeKanbanFilter, setActiveKanbanFilter] = useState<string | null>(null);

  // â”€â”€ Queries â”€â”€
  const { data: summaryRes, error: summaryError } = useGetFinanceSummary(selectedSeason);
  const { data: pipelineDataRes, error: pipelineError } = useListSponsorshipPipeline(selectedSeason);
  const { data: transactionsDataRes, error: transactionsError } = useListFinanceTransactions(selectedSeason);

  const summary = summaryRes;
  const pipeline = pipelineDataRes?.pipeline || [];
  const transactions = transactionsDataRes?.transactions || [];
  const isError = !!(summaryError || pipelineError || transactionsError);

  // â”€â”€ Mutations â”€â”€
  const savePipeline = useSaveSponsorshipPipeline();
  const saveTransaction = useSaveFinanceTransaction();
  const deleteTransaction = useDeleteFinanceTransaction();
  const deletePipeline = useDeleteSponsorshipPipeline();

  const handleSavePipeline = (data: z.infer<typeof sponsorshipPipelineSchema>) => {
    const result = sponsorshipPipelineSchema.safeParse(data);
    if (!result.success) {
      const firstError = result.error.issues[0];
      toast.error(`Validation error: ${firstError.message}`);
      return;
    }
    savePipeline.mutate(result.data, {
      onSuccess: () => {
        toast.success("Sponsorship updated.");
        setIsAdding(false);
        pipelineForm.reset();
      },
      onError: (err: Error) => {
        toast.error(`Failed to save lead: ${err.message || "Unknown error"}`);
      }
    });
  };

  const handleSaveTransaction = (data: z.infer<typeof financeTransactionSchema>) => {
    const result = financeTransactionSchema.safeParse(data);
    if (!result.success) {
      const firstError = result.error.issues[0];
      toast.error(`Validation error: ${firstError.message}`);
      return;
    }
    saveTransaction.mutate(result.data, {
      onSuccess: () => {
        toast.success("Transaction recorded.");
        setIsAdding(false);
        transactionForm.reset();
      },
      onError: (err: Error) => {
        toast.error(`Failed to save transaction: ${err.message || "Unknown error"}`);
      }
    });
  };

  const handleDeleteTransaction = (id: string) => {
    deleteTransaction.mutate(id, {
      onSuccess: () => toast.success("Transaction deleted."),
      onError: (err: Error) => toast.error(`Failed to delete: ${err.message}`)
    });
  };

  const handleDeletePipeline = (id: string) => {
    deletePipeline.mutate(id, {
      onSuccess: () => toast.success("Pipeline item deleted."),
      onError: (err: Error) => toast.error(`Failed to delete: ${err.message}`)
    });
  };

  // â”€â”€ Forms â”€â”€
  const pipelineForm = useForm({
    defaultValues: { company_name: "", status: "potential" as const, estimated_value: 0, seasonId: selectedSeason }
  });

  const transactionForm = useForm({
    defaultValues: { type: "expense" as const, amount: 0, category: "parts", date: new Date().toISOString().split('T')[0], description: "", seasonId: selectedSeason }
  });

  const isInitialLoading = !summaryRes && !isError;

  if (isError) {
    return (
      <div className="p-8 bg-ares-red/10 border border-ares-red/20 ares-cut-lg text-center">
        <RefreshCw className="mx-auto mb-4 text-ares-red animate-spin" size={32} />
        <h3 className="text-ares-red font-black uppercase tracking-widest text-lg mb-2">Financial Link Severed</h3>
        <p className="text-marble/60 text-sm mb-4">An error occurred while connecting to the team ledger.</p>
        <div className="font-mono text-[10px] py-1 px-2 bg-black/40 text-ares-red/80 inline-block ares-cut-sm">
          STATUS: ERROR
        </div>
      </div>
    );
  }

  if (isInitialLoading || !summary) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] gap-4">
        <RefreshCw className="text-ares-cyan animate-spin" size={48} />
        <p className="text-marble/60 font-black uppercase tracking-widest animate-pulse">Syncing Ledger...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Overview Metrics */}
      <DashboardMetricsGrid 
        metrics={[
          { label: "Total Income", value: `$${(summary?.total_income ?? 0).toLocaleString()}`, icon: <TrendingUp className="text-ares-green" /> },
          { label: "Total Expenses", value: `$${(summary?.total_expenses ?? 0).toLocaleString()}`, icon: <TrendingDown className="text-ares-red" /> },
          { label: "Cash Balance", value: `$${(summary?.balance ?? 0).toLocaleString()}`, icon: <Wallet className="text-ares-gold" /> },
          { label: "Pipeline Value", value: `$${pipeline.reduce((acc: number, p: PipelineItem) => acc + (p.status !== 'lost' ? (Number(p.estimated_value) || 0) : 0), 0).toLocaleString()}`, icon: <PieChart className="text-ares-cyan" /> },
        ]}
      />

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="flex bg-black/40 p-1 ares-cut-sm border border-white/5">
          <button 
            onClick={() => { setActiveTab("pipeline"); setIsAdding(false); }}
            className={`px-4 py-2 text-xs font-black uppercase tracking-widest transition-all ares-cut-sm ${activeTab === 'pipeline' ? 'bg-ares-red text-white' : 'text-marble/60 hover:text-white'}`}
          >
            Sponsorship Pipeline
          </button>
          <button 
            onClick={() => { setActiveTab("ledger"); setIsAdding(false); }}
            className={`px-4 py-2 text-xs font-black uppercase tracking-widest transition-all ares-cut-sm ${activeTab === 'ledger' ? 'bg-ares-red text-white' : 'text-marble/60 hover:text-white'}`}
          >
            Ledger & Expenses
          </button>
        </div>

        <SeasonPicker value={selectedSeason || ""} onChange={(v) => setSelectedSeason(v ? parseInt(v) : null)} />
      </div>

      <DashboardPageHeader
        title={activeTab === 'pipeline' ? "Sponsorship Pipeline" : "Financial Ledger"}
        subtitle={activeTab === 'pipeline' ? "Track potential funding sources and company outreach." : "Record every income and expense for the team's budget."}
        icon={activeTab === 'pipeline' ? <Building className="text-ares-cyan" /> : <DollarSign className="text-ares-gold" />}
        action={
          <button
            onClick={() => setIsAdding(!isAdding)}
            className="flex items-center gap-2 px-4 py-2 bg-ares-red text-white font-bold ares-cut-sm hover:bg-ares-danger transition-colors shadow-lg shadow-ares-red/20"
          >
            {isAdding ? <XCircle size={18} /> : <Plus size={18} />}
            {isAdding ? "Cancel" : activeTab === 'pipeline' ? "Add Lead" : "Add Transaction"}
          </button>
        }
      />

      {/* Add Form */}
      <AnimatePresence>
        {isAdding && (
          <motion.div
            initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}
            className="bg-obsidian border border-ares-red/30 ares-cut-lg p-8 shadow-2xl"
          >
            {activeTab === 'pipeline' ? (
              <form onSubmit={pipelineForm.handleSubmit(data => handleSavePipeline({ ...data, seasonId: selectedSeason || undefined }))} className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <DashboardInput id="pipeline-company" label="Company Name" {...pipelineForm.register("company_name")} error={pipelineForm.formState.errors.company_name?.message} fullWidth />
                <DashboardInput id="pipeline-value" label="Est. Value ($)" type="number" {...pipelineForm.register("estimated_value")} error={pipelineForm.formState.errors.estimated_value?.message} />
                <div className="flex flex-col gap-1">
                  <label htmlFor="pipeline-status" className="text-[10px] font-black uppercase tracking-widest text-marble/60 px-1">Initial Status</label>
                  <select id="pipeline-status" {...pipelineForm.register("status")} className="bg-white/5 border border-white/10 ares-cut-sm p-3 text-sm text-white focus:border-ares-red outline-none">
                    {PIPELINE_COLUMNS.map(c => <option key={c} value={c} className="bg-obsidian text-white">{pipelineConfig[c].label}</option>)}
                  </select>
                </div>
                <div className="md:col-span-3">
                  <DashboardSubmitButton isPending={savePipeline.isPending} defaultText="Add Lead to Pipeline" theme="red" />
                </div>
              </form>
            ) : (
              <form onSubmit={transactionForm.handleSubmit(data => handleSaveTransaction({ ...data, seasonId: selectedSeason || undefined }))} className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="flex flex-col gap-1">
                  <label htmlFor="transaction-type" className="text-[10px] font-black uppercase tracking-widest text-marble/60 px-1">Type</label>
                  <select id="transaction-type" {...transactionForm.register("type")} className="bg-white/5 border border-white/10 ares-cut-sm p-3 text-sm text-white focus:border-ares-red outline-none">
                    <option value="expense" className="bg-obsidian text-white">Expense (-)</option>
                    <option value="income" className="bg-obsidian text-white">Income (+)</option>
                  </select>
                </div>
                <DashboardInput id="ledger-amount" label="Amount ($)" type="number" step="0.01" {...transactionForm.register("amount")} error={transactionForm.formState.errors.amount?.message} />
                <DashboardInput id="ledger-date" label="Date" type="date" {...transactionForm.register("date")} />
                <DashboardInput id="ledger-category" label="Category" {...transactionForm.register("category")} placeholder="e.g. Parts, Travel, Reg" />
                <DashboardInput id="ledger-desc" label="Description" {...transactionForm.register("description")} placeholder="Details about the transaction..." fullWidth />
                <div className="md:col-span-3">
                  <DashboardSubmitButton isPending={saveTransaction.isPending} defaultText="Record Transaction" theme="red" />
                </div>
              </form>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Main View */}
      {activeTab === 'pipeline' ? (
        <>
          <GenericKanbanBoard<PipelineItem>
            items={pipeline}
            columns={PIPELINE_COLUMNS}
            columnConfig={pipelineConfig}
            getId={(item) => String(item.id)}
            getStatus={(item) => item.status}
            getSortOrder={(_item) => 0} // no sort order in DB currently
            onReorder={(updates) => {
              // we only care about status updates since sortOrder is not saved
              // to optimize, just update the items that changed status
              updates.forEach(update => {
                const item = pipeline.find((p: PipelineItem) => String(p.id) === update.id);
                if (item && item.status !== update.status) {
                  const pipelineItem = item as PipelineItem & { id?: string; seasonId?: number | null };
                  savePipeline.mutate({
                    id: pipelineItem.id,
                    company_name: pipelineItem.company_name,
                    status: update.status as "potential" | "contacted" | "pledged" | "secured" | "lost",
                    estimated_value: Number(pipelineItem.estimated_value),
                    contact_person: pipelineItem.contact_person ?? null,
                    notes: pipelineItem.notes ?? null,
                    seasonId: pipelineItem.seasonId ?? null,
                    assignees: pipelineItem.assignees ?? [],
                  });
                }
              });
            }}
            isLoading={isInitialLoading}
            activeFilter={activeKanbanFilter}
            onFilterChange={setActiveKanbanFilter}
            emptyStateText="No leads"
            renderItem={(item) => (
              <SortablePipelineCard
                key={item.id}
                item={item}
                onDelete={(id) => handleDeletePipeline(id)}
                onEdit={(item) => setEditingLead(item)}
              />
            )}
            renderDragOverlay={(item) => (
              <div className="p-3 bg-obsidian/90 ares-cut-sm border border-ares-cyan/40 shadow-lg shadow-ares-cyan/10 cursor-grabbing">
                <p className="text-sm font-bold text-white leading-tight">{item.company_name}</p>
              </div>
            )}
          />

          <AnimatePresence>
            {editingLead && (
              <SponsorshipEditModal
                item={editingLead}
                onClose={() => setEditingLead(null)}
                onSave={async (id, updates) => {
                  const lead = editingLead as PipelineItem & { id?: string };
                  const updatePayload: SponsorshipPipelinePayload = {
                    id: lead.id,
                    company_name: updates.company_name ?? lead.company_name,
                    status: updates.status ?? lead.status,
                    estimated_value: Number(updates.estimated_value ?? lead.estimated_value),
                    contact_person: updates.contact_person ?? lead.contact_person ?? null,
                    notes: updates.notes ?? lead.notes ?? null,
                    seasonId: updates.seasonId ?? lead.seasonId ?? null,
                    assignees: updates.assignees ?? lead.assignees ?? [],
                  };
                  handleSavePipeline(updatePayload);
                  setEditingLead(null);
                }}
                onDelete={(id) => {
                  handleDeletePipeline(id);
                  setEditingLead(null);
                }}
              />
            )}
          </AnimatePresence>
        </>
      ) : (
        <div className="bg-black/40 border border-white/5 ares-cut-lg overflow-hidden">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/5 border-b border-white/5">
                <th className="p-4 text-[10px] font-black uppercase tracking-widest text-marble/60">Date</th>
                <th className="p-4 text-[10px] font-black uppercase tracking-widest text-marble/60">Category</th>
                <th className="p-4 text-[10px] font-black uppercase tracking-widest text-marble/60">Description</th>
                <th className="p-4 text-[10px] font-black uppercase tracking-widest text-marble/60 text-right">Amount</th>
                <th className="p-4 w-10"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {transactions.map((t: TransactionItem) => (
                <tr key={t.id} className="hover:bg-white/5 transition-colors group">
                  <td className="p-4 text-xs font-bold text-marble/60">{t.date}</td>
                  <td className="p-4">
                    <span className="px-2 py-0.5 bg-white/5 border border-white/10 ares-cut-sm text-[10px] font-black uppercase tracking-widest text-marble">
                      {t.category}
                    </span>
                  </td>
                  <td className="p-4 text-sm text-white font-medium">{t.description || "â€”"}</td>
                  <td className={`p-4 text-sm font-black text-right ${t.type === 'income' ? 'text-ares-green' : 'text-ares-red'}`}>
                    {t.type === 'income' ? '+' : '-'}${Number(t.amount).toLocaleString()}
                  </td>
                  <td className="p-4">
                    <button 
                      onClick={() => confirm("Delete transaction?") && handleDeleteTransaction(t.id!)} 
                      className="opacity-0 group-hover:opacity-100 text-marble/20 hover:text-ares-red transition-all"
                      title="Delete transaction"
                      aria-label="Delete transaction"
                    >
                      <Trash2 size={14} />
                    </button>
                  </td>
                </tr>
              ))}
              {transactions.length === 0 && (
                <tr>
                  <td colSpan={5} className="p-12 text-center">
                    <DashboardEmptyState icon={<RefreshCw size={48} />} message="No transactions recorded for this season." />
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

const XCircle = ({ size }: { size: number }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
);

import { describe, it, expect, vi, beforeEach } from "vitest";
import { render, screen, fireEvent } from "@testing-library/react";
import React from "react";
import { ContactForm } from "./ContactForm";
import type { ProfileData } from "./types";

const mockSetProfile = vi.fn();

const defaultProfile: ProfileData = {
  phone: "",
  contactEmail: "",
  showPhone: false,
  showEmail: false,
} as ProfileData;

// Create a mock TanStack Form-like object
const createMockForm = (profile: ProfileData) => ({
  Field: ({ name, children }: any) => {
    const field = {
      name,
      state: {
        value: (profile as any)[name],
        meta: { errors: [] }
      },
      handleBlur: vi.fn(),
      handleChange: (val: any) => {
        mockSetProfile((prev: any) => ({ ...prev, [name]: val }));
      }
    };
    return children(field);
  }
});

const defaultProps = {
  form: createMockForm(defaultProfile) as any,
  isMinor: false,
  inputClass: "w-full bg-white/5 border border-white/10 px-4 py-2 text-white",
  labelClass: "text-xs font-bold uppercase tracking-widest text-marble/50",
  sectionClass: "space-y-4",
};

describe("ContactForm Component", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockSetProfile.mockImplementation((updater) => {
      if (typeof updater === "function") {
        return updater(defaultProfile);
      }
      return updater;
    });
  });

  it("renders nothing when isMinor is true", () => {
    render(<ContactForm {...defaultProps} isMinor={true} />);
    expect(screen.queryByText("Contact")).not.toBeInTheDocument();
  });

  it("renders contact section when isMinor is false", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    expect(screen.getByText("Contact (Optional)")).toBeInTheDocument();
  });

  it("renders phone input field", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const phoneInput = screen.getByLabelText("Phone");
    expect(phoneInput).toBeInTheDocument();
    expect(phoneInput).toHaveAttribute("placeholder", "(304) 555-1234");
  });

  it("renders contact email input field", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const emailInput = screen.getByLabelText("Contact Email");
    expect(emailInput).toBeInTheDocument();
    expect(emailInput).toHaveAttribute("type", "email");
  });

  it("renders show phone checkbox", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const showPhoneCheckbox = screen.getByRole("checkbox", { name: /show phone number on public profile/i });
    expect(showPhoneCheckbox).toBeInTheDocument();
  });

  it("renders show email checkbox", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const showEmailCheckbox = screen.getByRole("checkbox", { name: /show email on public profile/i });
    expect(showEmailCheckbox).toBeInTheDocument();
  });

  it("updates phone value when user types", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const phoneInput = screen.getByLabelText("Phone");
    fireEvent.change(phoneInput, { target: { value: "(304) 555-1234" } });
    expect(mockSetProfile).toHaveBeenCalled();
  });

  it("updates contact email value when user types", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const emailInput = screen.getByLabelText("Contact Email");
    fireEvent.change(emailInput, { target: { value: "user@example.com" } });
    expect(mockSetProfile).toHaveBeenCalled();
  });

  it("toggles showPhone checkbox", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const showPhoneCheckbox = screen.getByRole("checkbox", { name: /show phone number on public profile/i });
    fireEvent.click(showPhoneCheckbox);
    expect(mockSetProfile).toHaveBeenCalled();
  });

  it("toggles showEmail checkbox", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const showEmailCheckbox = screen.getByRole("checkbox", { name: /show email on public profile/i });
    fireEvent.click(showEmailCheckbox);
    expect(mockSetProfile).toHaveBeenCalled();
  });

  it("initializes with existing phone value", () => {
    const customProfile = { ...defaultProfile, phone: "(555) 123-4567" };
    const props = { ...defaultProps, form: createMockForm(customProfile) as any };
    render(<ContactForm {...props} />);
    const phoneInput = screen.getByLabelText("Phone") as HTMLInputElement;
    expect(phoneInput.value).toBe("(555) 123-4567");
  });

  it("initializes with existing contact email value", () => {
    const customProfile = { ...defaultProfile, contactEmail: "existing@example.com" };
    const props = { ...defaultProps, form: createMockForm(customProfile) as any };
    render(<ContactForm {...props} />);
    const emailInput = screen.getByLabelText("Contact Email") as HTMLInputElement;
    expect(emailInput.value).toBe("existing@example.com");
  });

  it("has proper input classes applied", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const phoneInput = screen.getByLabelText("Phone");
    expect(phoneInput).toHaveClass("w-full");
    expect(phoneInput).toHaveClass("bg-white/5");
  });

  it("has proper section heading styling", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const heading = screen.getByText("Contact (Optional)");
    expect(heading).toHaveClass("text-ares-red");
  });

  it("has proper accessibility labels for checkboxes", () => {
    render(<ContactForm {...defaultProps} isMinor={false} />);
    const showPhoneCheckbox = screen.getByRole("checkbox", { name: /show phone number on public profile/i });
    expect(showPhoneCheckbox).toHaveAttribute("aria-label", "Show phone number on public profile");
  });
});

import { ProfileFormSubComponentProps } from "./types";

export function ContactForm({ form, isMinor, inputClass, labelClass, sectionClass }: ProfileFormSubComponentProps) {
	if (isMinor) return null;

	return (
		<div className={sectionClass}>
			<h3 className="text-sm font-black uppercase tracking-wider text-ares-red">Contact (Optional)</h3>
			<div className="grid grid-cols-1 md:grid-cols-2 gap-4">
				<div>
					<label htmlFor="pe-phone" className={labelClass}>Phone</label>
					<form.Field
						name="phone"
						children={(field) => (
							<>
								<input
									id="pe-phone"
									name={field.name}
									type="tel"
									value={field.state.value}
									onBlur={field.handleBlur}
									onChange={(e) => field.handleChange(e.target.value)}
									className={inputClass}
									placeholder="(304) 555-1234"
								/>
								<form.Field
									name="showPhone"
									children={(showField) => (
										<label className="flex items-center gap-2 mt-2 text-xs text-ares-gray">
											<input
												type="checkbox"
												name={showField.name}
												checked={showField.state.value}
												onChange={(e) => showField.handleChange(e.target.checked)}
												className="accent-ares-red"
												aria-label="Show phone number on public profile"
											/>
											Show on public profile
										</label>
									)}
								/>
							</>
						)}
					/>
				</div>
				<div>
					<label htmlFor="pe-contact-email" className={labelClass}>Contact Email</label>
					<form.Field
						name="contactEmail"
						children={(field) => (
							<>
								<input
									id="pe-contact-email"
									name={field.name}
									type="email"
									pattern="[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$"
									title="Please enter a valid email address"
									value={field.state.value}
									onBlur={field.handleBlur}
									onChange={(e) => field.handleChange(e.target.value)}
									className={inputClass}
									placeholder="Optional. Replaces login email."
								/>
								<form.Field
									name="showEmail"
									children={(showField) => (
										<label className="flex items-center gap-2 mt-2 text-xs text-ares-gray">
											<input
												type="checkbox"
												name={showField.name}
												checked={showField.state.value}
												onChange={(e) => showField.handleChange(e.target.checked)}
												className="accent-ares-red"
												aria-label="Show email on public profile"
											/>
											Show email on public profile
										</label>
									)}
								/>
							</>
						)}
					/>
				</div>
			</div>
		</div>
	);
}

import { ProfileFormSubComponentProps } from "./types";

const DIETARY_OPTIONS = ["Gluten-Free", "Kosher", "Halal", "Vegetarian", "Vegan", "Nut-free", "No-pork", "No-Beef"];

export function FunFirstSection({ form, inputClass, labelClass, sectionClass }: ProfileFormSubComponentProps) {
	const dietaryRestrictions = form.getFieldValue("dietaryRestrictions");

	const toggleDietary = (item: string) => {
		const current = form.getFieldValue("dietaryRestrictions");
		form.setFieldValue("dietaryRestrictions", current.includes(item)
			? current.filter(t => t !== item)
			: [...current, item]
		);
	};

	const getOtherDietary = () => {
		const other = dietaryRestrictions.find(t => t.startsWith("Other:"));
		return other ? other.replace("Other:", "").trim() : "";
	};

	const setOtherDietary = (val: string) => {
		const current = form.getFieldValue("dietaryRestrictions");
		const filtered = current.filter(t => !t.startsWith("Other:"));
		if (!val) {
			form.setFieldValue("dietaryRestrictions", filtered);
		} else {
			form.setFieldValue("dietaryRestrictions", [...filtered, `Other: ${val}`]);
		}
	};

	return (
		<div className={sectionClass}>
			<h3 className="text-sm font-black uppercase tracking-wider text-ares-red">FIRST & Fun</h3>
			<div>
				<label htmlFor="pe-fav-first" className={labelClass}>Favorite thing about FIRST / ARES</label>
				<form.Field
					name="favoriteFirstThing"
					children={(field) => (
						<input
							id="pe-fav-first"
							name={field.name}
							value={field.state.value}
							onBlur={field.handleBlur}
							onChange={(e) => field.handleChange(e.target.value)}
							className={inputClass}
							placeholder="Building robots with friends!"
						/>
					)}
				/>
			</div>
			<div className="grid grid-cols-1 md:grid-cols-2 gap-4">
				<div>
					<label htmlFor="pe-fav-mech" className={labelClass}>Favorite Robot Mechanism</label>
					<form.Field
						name="favoriteRobotMechanism"
						children={(field) => (
							<input
								id="pe-fav-mech"
								name={field.name}
								value={field.state.value}
								onBlur={field.handleBlur}
								onChange={(e) => field.handleChange(e.target.value)}
								className={inputClass}
								placeholder="e.g. 2022 Turret"
							/>
						)}
					/>
				</div>
				<div>
					<label htmlFor="pe-superstition" className={labelClass}>Pre-Match Superstition</label>
					<form.Field
						name="preMatchSuperstition"
						children={(field) => (
							<input
								id="pe-superstition"
								name={field.name}
								value={field.state.value}
								onBlur={field.handleBlur}
								onChange={(e) => field.handleChange(e.target.value)}
								className={inputClass}
								placeholder="e.g. Taping the battery 3 times"
							/>
						)}
					/>
				</div>
			</div>
			<div className="grid grid-cols-1 md:grid-cols-2 gap-4">
				<div>
					<label htmlFor="pe-food" className={labelClass}>Favorite Food</label>
					<form.Field
						name="favoriteFood"
						children={(field) => (
							<input
								id="pe-food"
								name={field.name}
								value={field.state.value}
								onBlur={field.handleBlur}
								onChange={(e) => field.handleChange(e.target.value)}
								className={inputClass}
								placeholder="Pizza, tacos..."
							/>
						)}
					/>
				</div>
				<div>
					<span className={labelClass}>Dietary Restrictions</span>
					<form.Field
						name="dietaryRestrictions"
						children={(field) => (
							<div className="grid grid-cols-2 gap-2 mt-2">
								{DIETARY_OPTIONS.map(opt => (
									<label key={opt} className="flex items-center gap-2 text-sm text-marble">
										<input
											type="checkbox"
											name={field.name}
											checked={field.state.value.includes(opt)}
											onChange={() => toggleDietary(opt)}
											className="accent-ares-red rounded w-4 h-4"
										/>
										{opt}
									</label>
								))}
								<div className="col-span-2 mt-1">
									<label className="flex items-center gap-2 text-sm text-marble mb-1">
										<input
											type="checkbox"
											checked={field.state.value.some(t => t.startsWith("Other:"))}
											onChange={(e) => {
												if (!e.target.checked) setOtherDietary("");
												else setOtherDietary("Optional Details");
											}}
											className="accent-ares-red rounded w-4 h-4"
										/>
										Other
									</label>
									{field.state.value.some(t => t.startsWith("Other:")) && (
										<input
											className={`${inputClass} !py-2`}
											placeholder="Please specify..."
											value={getOtherDietary()}
											onChange={(e) => setOtherDietary(e.target.value)}
										/>
									)}
								</div>
							</div>
						)}
					/>
				</div>
			</div>
		</div>
	);
}

